//! `node.render_scene` — multi-object 3D scene renderer: N objects drawn
//! into ONE shared depth buffer (real occlusion between objects) lit by
//! any number of shared lights.
//!
//! Hand-written dynamic [`EffectNode`] (mux_texture-shaped, NOT the
//! `primitive!` macro): the `objects` param and `lights` param each
//! rebuild the port list in [`reconfigure`](EffectNode::reconfigure) —
//! same pattern as `node.switch_texture`'s `num_inputs`. Object count has
//! no structural cap — per-object port names (`mesh_{i}`, `transform_{i}`,
//! …) are generated by `format!` into the `Cow<'static, str>` name fields, and
//! the draw path issues one draw call per object. `OBJECT_SAFETY_MAX` is
//! a real safety bound (1024, GLB_CONFORMANCE_DESIGN.md D4) — a producer
//! that would exceed it must error, never truncate; it also doubles as the
//! editor slider's advisory range. Light count is
//! likewise uncapped: lights ride a runtime-sized `@binding(8)` storage
//! buffer, and `LIGHT_SLIDER_MAX` is only the editor slider's soft bound.
//!
//! `node.render_mesh` / `node.render_copies` each render into their own
//! private depth buffer — objects from either of those primitives cannot
//! occlude each other. `render_scene` closes that gap: every object draws
//! into ONE shared 4x-MSAA colour+depth target (cleared once) via
//! `manifold_gpu`'s `draw_instanced_depth_msaa_batch`, so the shared depth
//! test resolves real occlusion regardless of draw order, and the pass
//! resolves out to the single-sample `color` output with alpha-to-coverage
//! antialiasing the cutout edges.
//!
//! Per docs/REALTIME_3D_DESIGN.md §5 P2 (shipped): shadow maps for the
//! first `MAX_SHADOW_CASTING_LIGHTS` lights whose `cast_shadows` is set (in
//! slot order) — one depth-only pre-pass per caster into a private
//! `Depth32Float` map, consumed by PCF (`textureSampleCompareLevel`) in the
//! lit fragment shaders; lights past the caster cap still illuminate. No
//! atmosphere/fog yet (P3). Lights ride a ring-buffered `@binding(8)`
//! storage buffer (no 4KB `setBytes` cap). Per
//! docs/SCENE_BUILD_AND_GROUP_PARAMS_DESIGN.md §2 D3 (P2 of that design,
//! amending REALTIME_3D D3): each object's per-object TRS is no longer a
//! plain param — `rebuild` emits an optional `transform_n: PortType::Transform`
//! port per object instead of the retired nine scattered position/rotation/
//! scale params, fed by a `node.transform_3d` atom (unwired = identity). This
//! closes "transforms not beat-addressable": an LFO wired into the
//! transform atom's `rot_y` scalar port spins the object; a `beat_ramp`
//! into `pos_z` is a drop hit. Old saves carry a one-time migration
//! (`crate::migrations::scene_transform_v1120` in `manifold-io`) that
//! synthesizes the atom and re-points any card binding. Each object also
//! has an optional `base_color_map_n` albedo/alpha input (M6 addendum) plus
//! four more optional per-object maps (IMPORT_FIDELITY_DESIGN.md D3/F-P2):
//! `normal_map_n` (tangent-space, glTF convention, cotangent-frame
//! reconstruction — D4), `mr_map_n` (glTF metallic-roughness packing:
//! G=roughness, B=metallic), `occlusion_map_n` (R channel, darkens only the
//! PBR diffuse IBL term), and `emissive_map_n` (sRGB, multiplied by the
//! material's emission factor, added after lighting in every material
//! kind). All unwired-safe (dummy-bound, byte-identical output). ONE shared
//! `envmap` input lights every PBR object in the scene (an environment map
//! is scene-wide by nature, not per-object).
//!
//! Per docs/REALTIME_3D_DESIGN.md §10 D11+P8 (shipped): each object also
//! grows an optional `instances_n: Array(InstanceTransform)` port. Wired,
//! that object draws `instance_count = buffer_size / 32` copies (main pass
//! AND every caster's shadow pass), each instance's world transform
//! composed as `model_n · T_instance` — instance TRS applies first, the
//! object group's `transform_n` second, so wiring the SAME `node.transform_3d`
//! into two object groups keeps their instances glued together under a
//! group move. Unwired = a cached 1-entry identity stub, drawn with count 1
//! — the same shared depth buffer that resolves inter-object occlusion now
//! resolves occlusion between instances and every other object too, which
//! `node.render_copies`' private-depth-buffer instancing cannot do inside a
//! scene.

use ahash::AHashMap;
use manifold_gpu::GpuBinding;

use crate::generators::mesh_common::{InstanceTransform, MeshVertex};
use crate::node_graph::atmosphere::Atmosphere;
use crate::node_graph::camera::Camera;
use crate::node_graph::effect_node::{
    EffectNode, EffectNodeContext, EffectNodeType, ParamValues,
};
use crate::node_graph::material::{AlphaMode, MapSamplerDesc, Material, MaterialKind};
use crate::node_graph::parameters::{ParamDef, ParamType, ParamValue};
use crate::node_graph::ports::{NodeInput, NodeOutput, NodePort, PortKind, PortType};
use crate::node_graph::primitive::PrimitiveDescription;

pub const RENDER_SCENE_TYPE_ID: &str = "node.render_scene";

/// 4x MSAA for the scene pass. On Apple Silicon TBDR the multisample
/// color + depth live in tile memory (memoryless) and resolve on-chip —
/// no extra VRAM, one resolve at pass end. Paired with alpha-to-coverage
/// so cutout (`AlphaMode::Mask`) edges antialias too.
const MSAA_SAMPLES: u32 = 4;

/// Real safety bound for object count — a GPU-limit guard, not a UI
/// convenience (GLB_CONFORMANCE_DESIGN.md D4). Object ports are generated by
/// `format!` in `rebuild`, and the draw path issues one draw call per
/// object, so nothing in the type system, the shader, or the GPU bindings
/// structurally limits object count; this constant exists solely to bound
/// port-list growth (each object adds 9 ports) to something sane, and
/// doubles as the editor slider's advisory range. Any producer that would
/// exceed it (the glTF importer, `gltf_import.rs`) must error loudly at
/// import time rather than truncate — see [`ImportReport`] and
/// `assemble_import_graph`. Raise freely if a future asset
/// legitimately needs more; it is still just a port-list guard, no
/// GPU/shader coupling.
///
/// [`ImportReport`]: crate::node_graph::gltf_import::ImportReport
pub(crate) const OBJECT_SAFETY_MAX: u32 = 1024;
/// Soft upper bound for the `lights` slider — NOT a structural cap. Lights
/// ride a runtime-sized `array<vec4<f32>>` storage buffer at `@binding(8)`
/// (two vec4s per light), so nothing in the shader or the ABI limits the
/// count; each light gets its own dynamic `light_N` port. 64 lights ×
/// 32 B = 2 KB, half the Metal `setBytes` ceiling of 4 KB. HARD CEILING:
/// `setBytes` caps at 4 KB = 127 lights — do NOT raise this past 127
/// without first switching the `@binding(8)` arm from `GpuBinding::Bytes`
/// to a pooled `GpuBuffer` (docs/RENDER_SCENE_UNBOUNDED_LIGHTS_DESIGN.md
/// §6).
const LIGHT_SLIDER_MAX: u32 = 64;

const DEFAULT_OBJECTS: u32 = 2;
const DEFAULT_LIGHTS: u32 = 1;

/// Shadow-caster cap (REALTIME_3D_DESIGN D4, F2 amendment). Shadow maps are
/// honoured for the first `K` lights *in slot order* whose
/// `cast_shadows == true`; lights beyond the first `K` casters still
/// illuminate the scene, they just cast no shadow. This is a SEPARATE,
/// tighter budget than the (uncapped) object/light sliders: it bounds the
/// worst case at `objects × K` shadow-depth draws (64 × 4 = 256), not
/// `objects × lights`. Bumpable like any cap — the shader's caster table
/// (`@binding(9)`) and shadow-map bindings (`@binding(10..)`) size to it.
pub(crate) const MAX_SHADOW_CASTING_LIGHTS: usize = 4;

/// Ring depth for the per-frame light storage buffer. The content thread is
/// triple-buffered and its tick loop waits on the surface from ~2 frames ago
/// (`content_thread.rs`), so up to ~2 frames of GPU work read a given
/// frame's light buffer while the CPU wants to write the next. Rotating
/// through `FRAMES_IN_FLIGHT` buffers guarantees the CPU never overwrites a
/// buffer the GPU is still reading — the correctness the single shared
/// `create_buffer_shared` buffer (mesh_pipeline/line_pipeline) leaves to
/// frame-pacing luck.
const FRAMES_IN_FLIGHT: usize = 3;

/// Per-caster shadow metadata, packed as 5 `vec4<f32>` into the
/// `@binding(9)` caster table (`MAX_SHADOW_CASTING_LIGHTS` slots, always
/// bound). Columns 0–3 are the light's `shadow_view_proj`; the 5th vec4 is
/// `(bias, kernel_half_width, texel_size, light_size)` — `light_size` is
/// the D12/PCSS spare `.w` (REALTIME_3D_DESIGN §11): zero for the fixed
/// Hard/Soft/VerySoft tiers, the light's `Contact { light_size }` value
/// otherwise, paired with a negative `kernel_half_width` sentinel that
/// tells `render_scene.wgsl`'s `shadow_factor` to run the PCSS branch
/// instead of the fixed-kernel PCF loop. Kept as a plain vec4 stride
/// (not a struct with a mat4 member) so the storage layout is unambiguous
/// through SPIRV-Cross → MSL — same discipline as the light buffer.
const CASTER_VEC4_STRIDE: usize = 5;

/// IMPORT_FIDELITY_DESIGN.md D2/F-P1: split-sum IBL. Prefiltered specular
/// chain base resolution + mip count. `PREFILTER_MIP_COUNT` mips span
/// roughness 0 (mip 0, base resolution) to roughness 1 (the last mip,
/// 16×8) — a fixed, compile-time-shared constant with
/// `render_scene.wgsl`'s `PREFILTER_MAX_MIP` (same discipline as
/// `MAX_SHADOW_CASTING_LIGHTS`/`CASTER_STRIDE` staying in sync across the
/// Rust/WGSL boundary).
const PREFILTER_BASE_WIDTH: u32 = 512;
const PREFILTER_BASE_HEIGHT: u32 = 256;
const PREFILTER_MIP_COUNT: u32 = 6;
/// Diffuse irradiance map resolution (D2's committed default).
const IRRADIANCE_WIDTH: u32 = 32;
const IRRADIANCE_HEIGHT: u32 = 16;
/// Split-sum BRDF LUT resolution (D2's committed default).
const BRDF_LUT_SIZE: u32 = 128;

const _: () = assert!(
    PREFILTER_BASE_WIDTH >> (PREFILTER_MIP_COUNT - 1) >= 1
        && PREFILTER_BASE_HEIGHT >> (PREFILTER_MIP_COUNT - 1) >= 1,
    "PREFILTER_MIP_COUNT must not shrink the chain below 1x1"
);

#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct PrefilterUniforms {
    dst_width: u32,
    dst_height: u32,
    src_width: u32,
    src_height: u32,
    roughness: f32,
    _pad0: f32,
    _pad1: f32,
    _pad2: f32,
}
const _: () = assert!(std::mem::size_of::<PrefilterUniforms>() == 32);

#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct IrradianceUniforms {
    dst_width: u32,
    dst_height: u32,
    src_width: u32,
    src_height: u32,
}
const _: () = assert!(std::mem::size_of::<IrradianceUniforms>() == 16);

#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct LutUniforms {
    width: u32,
    height: u32,
    _pad0: f32,
    _pad1: f32,
}
const _: () = assert!(std::mem::size_of::<LutUniforms>() == 16);

// Per-object AND per-light port names are generated on demand
// (`mesh_{i}`, `transform_{i}`, `light_{i}`, …) now that `NodePort.name` is
// `Cow<'static, str>` — no static name tables, no object cap, no light cap.

// `static`, not `const`: `NodePort.name` is now `Cow<'static, str>`, whose
// `Owned` variant carries drop glue, so `&RENDER_SCENE_OUTPUTS` can no longer
// be rvalue-static-promoted out of a `const`. A `static` gives the slice a
// genuine `'static` address to borrow.
static RENDER_SCENE_OUTPUTS: [NodeOutput; 3] = [
    NodePort {
        name: std::borrow::Cow::Borrowed("color"),
        ty: PortType::Texture2D,
        kind: PortKind::Output,
        required: false,
    },
    // GBUFFER_DESIGN.md §2 D1: lazy — rendered ONLY when wired (same rule
    // as `render_mesh`'s `world_pos`/`world_normal`). Raw [0,1] clip depth
    // (D2), `R32Float` via the `output_format` override below.
    NodePort {
        name: std::borrow::Cow::Borrowed("depth"),
        ty: PortType::Texture2D,
        kind: PortKind::Output,
        required: false,
    },
    // GBUFFER_DESIGN.md §2 D5 (P2): lazy, same D1 rule as `depth`. NDC-space
    // per-pixel motion (camera + rigid-object motion only — see D5's
    // documented v1 limitation), `Rg16Float` via `output_format` below.
    NodePort {
        name: std::borrow::Cow::Borrowed("velocity"),
        ty: PortType::Texture2D,
        kind: PortKind::Output,
        required: false,
    },
];

/// Per-object uniform, one draw call per object. Superset shape shared
/// with `render_3d_mesh.wgsl`'s Material fields, plus a per-object
/// `model` matrix. Lights are NOT here — they live in the runtime-sized
/// `@binding(8)` storage buffer (see `evaluate`). See
/// `shaders/render_scene.wgsl` for the authoritative layout comment.
#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct RenderSceneUniforms {
    view_proj: [[f32; 4]; 4],
    model: [[f32; 4]; 4],
    camera_pos: [f32; 4],
    base_color: [f32; 4],
    emission: [f32; 4],
    /// `x`: metallic `[0,1]`, `y`: roughness `[0.01,1]`. `z`/`w` were
    /// permanently-zero reserved slots until GLB_CONFORMANCE_DESIGN.md
    /// G-P4/D5 repurposed them: `z` = `ior` (KHR_materials_ior, default
    /// `1.5`), `w` = `specular_factor` (KHR_materials_specular, default
    /// `1.0`) — both feed `fs_pbr`'s dielectric F0 term. Defaults collapse
    /// the formula to the pre-G-P4 hardcoded `F0 = 0.04` exactly, so this
    /// reuse is byte-identical for every asset without the extensions.
    pbr_metallic_roughness: [f32; 4],
    specular: [f32; 4],
    /// GLB_CONFORMANCE_DESIGN.md G-P4/D5: `KHR_materials_specular`'s
    /// `specularColorFactor` (rgb, default `[1,1,1]`) — `w` reserved.
    /// A NEW field (not a reserved-slot reuse) since no existing vec4 had
    /// 3 free floats for the rgb triplet.
    pbr_specular_tint: [f32; 4],
    /// GLB_CONFORMANCE_DESIGN.md G-P4/D5: per-map `KHR_texture_transform`
    /// folded 2×3 affines, one `vec4 + vec4` pair per map family. `*_uv_m`
    /// = linear part `(m00, m01, m10, m11)` s.t. `uv' = (m00*u + m01*v +
    /// tx, m10*u + m11*v + ty)`, default identity `(1,0,0,1)`; `*_uv_t` =
    /// translation `(tx, ty, 0, 0)` (`z`/`w` reserved), default zero.
    /// Per-map, not one shared transform: the AMG GT3 carries transforms
    /// on 9 normalTexture infos and only 1 baseColorTexture.
    base_color_uv_m: [f32; 4],
    base_color_uv_t: [f32; 4],
    normal_uv_m: [f32; 4],
    normal_uv_t: [f32; 4],
    mr_uv_m: [f32; 4],
    mr_uv_t: [f32; 4],
    occlusion_uv_m: [f32; 4],
    occlusion_uv_t: [f32; 4],
    emissive_uv_m: [f32; 4],
    emissive_uv_t: [f32; 4],
    cel_params: [f32; 4],
    /// `x` = 1.0 when `normal_map_n` is wired (IMPORT_FIDELITY_DESIGN.md
    /// D3/F-P2, tangent-space cotangent-frame reconstruction), `z` = 1.0
    /// when `base_color_map_n` is wired (M6 addendum, matches
    /// `resolve_albedo`'s gate); `y`/`w` stay zero permanently — the old
    /// single-channel roughness_map/metallic_map stubs, superseded by
    /// the dedicated `mr_map_n` (see `texture_flags2` below).
    texture_flags: [f32; 4],
    /// IMPORT_FIDELITY_DESIGN.md D3/F-P2: `texture_flags` above is full, so
    /// the three remaining new per-object maps get their own vec4. `x` =
    /// `mr_map_n` wired, `y` = `occlusion_map_n` wired, `z` =
    /// `emissive_map_n` wired, `w` reserved.
    texture_flags2: [f32; 4],
    /// `x` = alpha_mode (1.0 = Mask/cutout, 0.0 = Opaque), `y` =
    /// alpha_cutoff. `z`/`w` were permanently-zero reserved slots until
    /// GLB_CONFORMANCE_DESIGN.md G-P5/D5 repurposed them: `z` = `clearcoat`
    /// (KHR_materials_clearcoat's `clearcoatFactor`, default `0.0`), `w` =
    /// `clearcoat_roughness` (`clearcoatRoughnessFactor`, default `0.0`) —
    /// both feed `fs_pbr`'s second GGX lobe. Default `0.0` makes the
    /// shader's energy-compensation weight exactly zero, byte-identical to
    /// pre-G-P5 output.
    alpha_params: [f32; 4],
    /// `(light_count, ambient, exposure_ev, 0)`. `light_count` is the sole
    /// source of truth for how many `@binding(8)` entries the shader reads —
    /// NOT `arrayLength` (D1). `exposure_ev` (CAMERA_AND_LENS_DESIGN.md §2
    /// D5, was zero-padded until P2) is the camera's `lens.exposure_ev` —
    /// the shader multiplies its final straight rgb by `exp2(exposure_ev)`.
    scene_params: [f32; 4],
    /// Atmosphere (P3): fog colour (rgb; a reserved). Scene-wide — the same
    /// values are copied into every object's uniform.
    fog_color: [f32; 4],
    /// `(fog_density, height_falloff, 0, 0)`. `fog_density == 0` → no fog
    /// (unwired atmosphere = byte-identical to no atmosphere).
    fog_params: [f32; 4],
    /// Scene-wide ambient/sky tint (rgb multiplier on the ambient term).
    ambient_tint: [f32; 4],
    /// VOLUMETRIC_LIGHT_DESIGN.md D1 (P1 plumbing only — no march kernel
    /// reads this yet). `x`: shaft_intensity (0 = off, THE fader), `y`:
    /// shaft_anisotropy (Henyey-Greenstein g), `z`: shaft_quality (0/1/2 =
    /// Low/Med/High, as f32), `w`: reserved.
    shaft_params: [f32; 4],
    /// GBUFFER_DESIGN.md §2 D5 (P2): previous frame's scene `view_proj`.
    /// Always present — one `Uniforms` layout shared by both the
    /// velocity-on and velocity-off pipeline variants (the velocity-off
    /// shader code simply never reads it). Seeded to THIS frame's
    /// `view_proj` on the node's very first `evaluate()` (no history yet),
    /// so first-frame velocity is exactly zero (see `RenderScene::evaluate`).
    prev_view_proj: [[f32; 4]; 4],
    /// GBUFFER_DESIGN.md §2 D5 (P2): this object's previous-frame `model`
    /// matrix. Same always-present / first-frame-seeded rule as
    /// `prev_view_proj`.
    prev_model: [[f32; 4]; 4],
    /// GLTF_MATERIAL_EXTENSIONS_DESIGN.md E1/D2: single aligned block,
    /// grown ONCE here, sized for ALL FIVE families the design phases in
    /// (sheen, iridescence, anisotropy, dispersion, transmission+volume) —
    /// E2-E6 only fill/read these fields, they never grow the struct
    /// again. Every default reproduces glTF's own implicit default
    /// (0.0/neutral), so every existing asset is byte-identical until a
    /// later phase's shader change reads a non-default value.
    /// `KHR_materials_sheen`: `xyz` = `sheenColorFactor` (default
    /// `[0,0,0]`, inert), `w` = `sheenRoughnessFactor` (default `0.0`).
    sheen_params: [f32; 4],
    /// `KHR_materials_iridescence`: `x` = `iridescenceFactor` (default
    /// `0.0`, inert), `y` = `iridescenceIor` (default `1.3`), `z` =
    /// `iridescenceThicknessMinimum` (default `100.0` nm), `w` =
    /// `iridescenceThicknessMaximum` (default `400.0` nm).
    iridescence_params: [f32; 4],
    /// `KHR_materials_anisotropy`'s `anisotropyStrength` (`x`, default
    /// `0.0`) + `anisotropyRotation` (`y`, default `0.0` rad) — only 2 of
    /// 4 floats, so `KHR_materials_dispersion`'s single factor (`z`,
    /// default `0.0`) shares this vec4 rather than costing its own
    /// (GLTF_MATERIAL_EXTENSIONS_DESIGN.md E1's explicit packing call).
    /// `w` reserved.
    anisotropy_dispersion_params: [f32; 4],
    /// `KHR_materials_transmission`'s `transmissionFactor` (`x`, default
    /// `0.0`) + `KHR_materials_volume`'s `thicknessFactor` (`y`, default
    /// `0.0`) and `attenuationDistance` (`z`, default the finite
    /// `VOLUME_ATTENUATION_DISTANCE_NO_ATTENUATION` sentinel —
    /// `gltf_load.rs`: glTF's own `+infinity` default isn't
    /// `serde_json`-safe). `w` reserved.
    transmission_volume_params: [f32; 4],
    /// `KHR_materials_volume`'s `attenuationColor` (`xyz`, default
    /// `[1,1,1]` — neutral). `w` reserved.
    volume_attenuation_color: [f32; 4],
}

// 736 = 46 × 16 → the naga 16-byte uniform-size rule holds. Was 480 before
// GLB_CONFORMANCE_DESIGN.md G-P4/D5: `pbr_specular_tint` + five per-map
// `*_uv_m`/`*_uv_t` pairs (+176 bytes, eleven new vec4s —
// `ior`/`specular_factor` rode existing reserved slots on
// `pbr_metallic_roughness` instead of growing the struct). Still 656 after
// G-P5/D5: `clearcoat`/`clearcoat_roughness` rode `alpha_params`'s two
// reserved slots — no struct growth. Now 736 after
// GLTF_MATERIAL_EXTENSIONS_DESIGN.md E1/D2: five new vec4s
// (`sheen_params`/`iridescence_params`/`anisotropy_dispersion_params`/
// `transmission_volume_params`/`volume_attenuation_color`, +80 bytes) —
// ONE migration sized for all five families this doc's phases add, per
// D2 (never grown again per-family).
const _: () = assert!(std::mem::size_of::<RenderSceneUniforms>() == 736);

/// Per-(caster, object) uniform for the shadow depth pass
/// (`shaders/shadow_depth.wgsl`). The vertex shader composes
/// `light_view_proj · model · position` and writes only depth. 128 bytes.
#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct ShadowUniforms {
    light_view_proj: [[f32; 4]; 4],
    model: [[f32; 4]; 4],
}
const _: () = assert!(std::mem::size_of::<ShadowUniforms>() == 128);

pub struct RenderScene {
    inputs: Vec<NodeInput>,
    params: Vec<ParamDef>,
    num_objects: u32,
    num_lights: u32,
    /// Keyed `(MaterialKind, emit_velocity)` — GBUFFER_DESIGN.md §2 D5
    /// (P2): the velocity-on/off pipeline variants are two DISTINCT
    /// compiled pipelines per material (function-constant text
    /// substitution, not a second WGSL file — see `pipeline_for`), so the
    /// cache key grows from `MaterialKind` alone. 4 materials × 2 = 8
    /// entries max.
    /// IMPORT_FIDELITY_DESIGN.md D8/F-P5: the cache key grows a third
    /// dimension, `is_blend` — a Blend-material pipeline has its own blend
    /// state and no alpha-to-coverage (see `pipeline_for`), so it is a
    /// distinct compiled pipeline from the opaque/mask one for the same
    /// `(kind, emit_velocity)`. 4 materials × 2 × 2 = 16 entries max.
    pipelines: AHashMap<(MaterialKind, bool, bool), manifold_gpu::GpuRenderPipeline>,
    depth_stencil: Option<manifold_gpu::GpuDepthStencilState>,
    /// IMPORT_FIDELITY_DESIGN.md D8/F-P5: depth TEST on (`Less`, matching
    /// `depth_stencil` above) but WRITE off — the sorted transparent
    /// group's depth-stencil state, drawn as `DepthMsaaPassDesc::second_pass`
    /// right after the opaque group in the same encoder pass.
    blend_depth_stencil: Option<manifold_gpu::GpuDepthStencilState>,
    /// Memoryless 4x-MSAA color + depth targets for the scene pass, sized
    /// to the render target. Both resolve on-chip; only `msaa_color`
    /// resolves out to the single-sample output.
    msaa_color: Option<manifold_gpu::GpuTexture>,
    depth_texture: Option<manifold_gpu::GpuTexture>,
    depth_width: u32,
    depth_height: u32,
    /// Memoryless 4x-MSAA `Rg16Float` velocity aux-MRT target
    /// (GBUFFER_DESIGN.md §2 D5, P2's `aux_color` slot). Allocated ONLY
    /// when `evaluate` finds the `velocity` output wired this frame (the
    /// D1 lazy rule) — an unwired scene never calls
    /// `ensure_velocity_msaa_target`, so it costs nothing.
    velocity_msaa: Option<manifold_gpu::GpuTexture>,
    velocity_width: u32,
    velocity_height: u32,
    /// Per-object-slot previous-frame `model` matrix (GBUFFER_DESIGN.md §2
    /// D5, P2), indexed by object slot `n`. `None` at a slot means "no
    /// history yet" — the frame that finds `None` there seeds
    /// `prev_model = model` (this frame's own value) so that object's
    /// first-ever velocity is exactly zero, not approximately. Resized and
    /// reset to all-`None` on every `rebuild` (an object-count change may
    /// reassign what slot `n` means, so any stale history there is
    /// discarded rather than risked).
    prev_model: Vec<Option<[[f32; 4]; 4]>>,
    /// Previous frame's scene `view_proj` (GBUFFER_DESIGN.md §2 D5, P2).
    /// `None` = no history yet (same first-frame seeding rule as
    /// `prev_model`); reset on every `rebuild`.
    prev_view_proj: Option<[[f32; 4]; 4]>,
    /// RAYTRACING_DESIGN.md §5.2 P4: monotonic per-node frame counter
    /// driving the camera-jitter sequence
    /// ([`crate::metalfx_temporal_upscaler::jitter_offset`]) when
    /// `temporal_upscale` is on. Incremented every `evaluate()` regardless
    /// of the param (cheap, and keeps the sequence phase stable if the
    /// toggle flips mid-session rather than restarting from index 0).
    /// NOT reset on `rebuild` — an object/light-count change doesn't
    /// invalidate the jitter phase the way `prev_model`/`prev_view_proj`
    /// history does.
    jitter_frame_index: u32,
    dummy_texture: Option<manifold_gpu::GpuTexture>,
    sampler: Option<manifold_gpu::GpuSampler>,
    /// GLB_XFAIL_BURNDOWN_DESIGN.md D3: per-map-family material samplers
    /// (bindings 22..26), keyed by [`sampler_cache_key`] — one entry per
    /// DISTINCT `MapSamplerDesc` seen so far, not per object or per family
    /// (most scenes share the same wrap/filter settings across every
    /// object, so this stays a handful of entries even in a 53-object
    /// scene). Metal sampler objects are trivially cheap to create; this
    /// cache exists only to avoid re-creating the same one every frame.
    /// Replaces the single hardcoded-REPEAT `material_sampler` (landed
    /// `85b5bb9d` — fixed the striped-helmet smear; see `ensure_material_sampler`
    /// for why the new per-family default still can't reintroduce it).
    material_samplers: AHashMap<u32, manifold_gpu::GpuSampler>,
    /// Ring of per-frame light storage buffers (see [`FRAMES_IN_FLIGHT`]).
    /// Grown on demand; rotated each `evaluate` so a frame's write never
    /// lands on a buffer an in-flight frame is still reading.
    light_buffers: Vec<manifold_gpu::GpuBuffer>,
    light_frame: usize,
    light_capacity: u64,
    /// Depth-only pipeline + depth-stencil state for the shadow passes.
    shadow_pipeline: Option<manifold_gpu::GpuRenderPipeline>,
    shadow_depth_stencil: Option<manifold_gpu::GpuDepthStencilState>,
    /// Per-caster private shadow maps, cached `(resolution, texture)`;
    /// recreated when a caster's `shadow_resolution` changes. Created
    /// `RENDER_TARGET | SHADER_READ` (AGX 0x78 guard).
    shadow_maps: [Option<(u32, manifold_gpu::GpuTexture)>; MAX_SHADOW_CASTING_LIGHTS],
    /// RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md D6 — per-caster shadow
    /// dirty-check key (a 64-bit hash of everything the shadow pass reads
    /// for that caster this frame — see the shadow loop below for the exact
    /// component list). `Some(key) == this frame's freshly computed key`
    /// means the persisted `shadow_maps[slot]` texture already holds this
    /// content, so the depth-only draw batch is skipped entirely (I1: ANY
    /// mismatch — including a `None` on the first frame — falls through to
    /// a real render and stores the new key; never served on a partial
    /// match).
    shadow_cache_keys: [Option<u64>; MAX_SHADOW_CASTING_LIGHTS],
    /// PCF comparison sampler (`compare = Less`).
    shadow_sampler: Option<manifold_gpu::GpuSampler>,
    /// 1×1 `Depth32Float` (`SHADER_READ`) bound to unused/non-caster
    /// shadow-map slots so every `@binding(10..)` is always a valid depth
    /// texture even in a scene with no casters.
    dummy_depth: Option<manifold_gpu::GpuTexture>,
    /// Cached 1-entry `Array(InstanceTransform)` bound to `instances_n`
    /// for any object that leaves it unwired: `pos_scale = [0,0,0,1]`,
    /// `rot_pad = [0,0,0,0]` — the same always-bind ABI-stub pattern as
    /// `dummy_depth` (D11). Drawn with `instance_count = 1`, so the
    /// vertex shader's `model_n · T_instance` composition collapses to
    /// exactly `model_n` — an unwired object costs one extra 32-byte L1
    /// storage-buffer read, nothing observable in the output.
    identity_instance_stub: Option<manifold_gpu::GpuBuffer>,
    /// VOLUMETRIC_LIGHT_DESIGN.md D3 (P2): half-res `Rgba16Float` light-shaft
    /// inscatter texture, lazily created via the `ensure_shadow_map` pattern
    /// ONLY when [`wants_shafts`] is true. Stays `None` when shafts are off
    /// (the `wants_shafts_gate` V1 test pins this half of the
    /// zero-cost-when-off contract).
    shaft_inscatter: Option<manifold_gpu::GpuTexture>,
    /// VOLUMETRIC_LIGHT_DESIGN.md D3 (P2): half-res `R32Float` point-sampled
    /// depth downsample, feeding both the march (ray-endpoint depth) and the
    /// upsample-composite (depth-similarity weights). Same lazy-creation
    /// rule as `shaft_inscatter`.
    shaft_depth_half: Option<manifold_gpu::GpuTexture>,
    /// Cached half-res dims the two textures above were last sized to
    /// (resize detection, same pattern as `depth_width`/`depth_height`).
    shaft_half_width: u32,
    shaft_half_height: u32,
    /// VOLUMETRIC_LIGHT_DESIGN.md D3 (P2): full-res `R32Float` internal
    /// depth resolve, used ONLY when shafts are on AND the graph's `depth`
    /// output is unwired — "shafts-on forces the internal Sample0 depth
    /// resolve even when `depth` is unwired" (D3). When `depth` IS wired,
    /// the march reads the graph-allocated resolve target directly and this
    /// stays `None`.
    shaft_depth_internal: Option<manifold_gpu::GpuTexture>,
    shaft_depth_internal_width: u32,
    shaft_depth_internal_height: u32,
    /// The three internal compute/render pipelines P2 adds. Not graph atoms
    /// (§2.5 audit: zero new graph primitives) — hand-written pipelines like
    /// `shadow_pipeline` above, built directly from `include_str!` WGSL, not
    /// the `primitive!` codegen path (that path is for user-wireable atoms;
    /// these are internal passes of the `render_*` draw-call boundary node,
    /// the same exemption class as `ensure_shadow_pass`).
    shaft_downsample_pipeline: Option<manifold_gpu::GpuComputePipeline>,
    shaft_march_pipeline: Option<manifold_gpu::GpuComputePipeline>,
    shaft_composite_pipeline: Option<manifold_gpu::GpuRenderPipeline>,
    /// IMPORT_FIDELITY_DESIGN.md D2/F-P1: split-sum IBL. Prefiltered
    /// specular mip chain (`PREFILTER_BASE_WIDTH`×`PREFILTER_BASE_HEIGHT`,
    /// `PREFILTER_MIP_COUNT` mips) — allocated ONCE (fixed size, never
    /// resized). RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md D7 (P3):
    /// re-convolved only when `ibl_cache_key` misses (see
    /// `run_ibl_convolution`'s doc comment for the generation-signal safety
    /// argument).
    prefiltered_specular: Option<manifold_gpu::GpuTexture>,
    /// Diffuse irradiance map (`IRRADIANCE_WIDTH`×`IRRADIANCE_HEIGHT`).
    irradiance_map: Option<manifold_gpu::GpuTexture>,
    /// Split-sum BRDF LUT (`BRDF_LUT_SIZE`²). Envmap-independent —
    /// computed ONCE per device, gated by `brdf_lut_built`, never rebuilt.
    brdf_lut: Option<manifold_gpu::GpuTexture>,
    brdf_lut_built: bool,
    /// RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md D7 (P3): the IBL dirty-check
    /// key the prefiltered-specular/irradiance convolution last ran with —
    /// a hash of (envmap slot write generation, envmap texture identity,
    /// executor rebuild epoch). `Some(key) == this frame's freshly computed
    /// key` means the persisted `prefiltered_specular`/`irradiance_map`
    /// textures already hold this exact envmap's convolution, so both
    /// dispatches are skipped. I2: never served on ANY mismatch, including
    /// `None` on first use or an unwired-to-wired transition (see
    /// `run_ibl_convolution`'s doc comment for the full safety argument).
    ibl_cache_key: Option<u64>,
    ibl_prefilter_pipeline: Option<manifold_gpu::GpuComputePipeline>,
    ibl_irradiance_pipeline: Option<manifold_gpu::GpuComputePipeline>,
    ibl_brdf_lut_pipeline: Option<manifold_gpu::GpuComputePipeline>,
    /// GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: single-sample snapshot of the
    /// fully-shaded opaque scene, blitted from `target` right after Pass A
    /// ends — the seam a later transmissive Pass B (E2b) samples to see
    /// "everything opaque behind this glass". `None` until a frame draws at
    /// least one `Blend` object with `transmission_factor > 0` — a
    /// zero-transmission scene never allocates this (same lazy-creation
    /// contract as `shaft_inscatter` above).
    opaque_scene_color: Option<manifold_gpu::GpuTexture>,
    opaque_scene_color_width: u32,
    opaque_scene_color_height: u32,
    opaque_scene_color_format: manifold_gpu::GpuTextureFormat,
    /// E2a: real single-sample `Depth32Float` snapshot of the opaque
    /// group's depth, populated by a dedicated camera-space depth-only
    /// prepass (reuses `shadow_pipeline`, fed the camera's `view_proj`
    /// instead of a light's) so Pass B can depth-test against it as an
    /// actual Metal depth ATTACHMENT. The existing MSAA pass's
    /// `depth_resolve` mechanism (`R32Float`) can't serve this: `R32Float`
    /// is a legal depth *resolve* destination but not a legal depth-
    /// ATTACHMENT pixel format. `None` when no transmissive object is in
    /// the scene this frame.
    opaque_depth_snapshot: Option<manifold_gpu::GpuTexture>,
    opaque_depth_snapshot_width: u32,
    opaque_depth_snapshot_height: u32,
    /// RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md P4 (R5): this object's port
    /// names, generated once in [`Self::rebuild`] instead of re-formatted
    /// every `evaluate()` call. §1's CPU row measured ~22 `format!`
    /// allocations per object per frame plus a linear `NodeInputs::slot`
    /// scan per lookup (`bindings.rs`) — together O(objects × wired_ports)
    /// ≈ O(objects²). `evaluate()` now indexes this `Vec` by object number
    /// and resolves each name through a per-frame [`bindings::Slot`] index
    /// (built once via `NodeInputs::build_index`) instead.
    /// SCENE_OBJECT_AND_PANEL_V2_DESIGN.md D4/P2: one `object_{i}` port
    /// name per object, pre-formatted once in [`Self::rebuild`] (only
    /// reached on an `objects` param change), same treatment
    /// `light_port_names` gets below. Replaces the 21 legacy per-object
    /// port-name families (`mesh_i`/`material_i`/17 maps/`transform_i`/
    /// `instances_i`) — every one of those resources now arrives bundled
    /// in the single `SceneObject` read off this one port.
    object_port_names: Vec<Box<str>>,
    /// Same treatment for `light_{i}` port names.
    light_port_names: Vec<Box<str>>,
}

/// VOLUMETRIC_LIGHT_DESIGN.md D1/V1: the sole CPU gate for the whole
/// light-shaft feature. `shaft_intensity <= 0` (the unwired default) means
/// the march must never run and no shaft texture is ever allocated — the
/// "unwired = zero cost" contract, extended from fog to shafts.
fn wants_shafts(atmosphere: &Atmosphere) -> bool {
    atmosphere.shaft_intensity > 0.0
}

/// D1's `shaft_quality` enum (0/1/2 = Low/Med/High) -> D2's committed march
/// step count (16/24/32). Any value past 2 clamps to High — the enum can
/// only ever carry 0..=2 (`AtmosphereNode`'s param clamps it), this is just
/// the CPU-side decode staying total.
fn shaft_step_count(quality: u32) -> u32 {
    match quality {
        0 => 16,
        1 => 24,
        _ => 32,
    }
}

/// Half-res march uniforms (VOLUMETRIC_LIGHT_DESIGN.md D2). Mirrors
/// `shaft_march.wgsl`'s `Uniforms` struct field-for-field — four vec4s of
/// camera basis (each carrying one derived scalar in `.w`), then fog/shaft
/// params, then march-loop scalars. 96 bytes = 6 x 16, naga's uniform-size
/// rule holds trivially since every member is already a vec4.
#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct ShaftMarchUniforms {
    camera_pos: [f32; 4],
    camera_right: [f32; 4],
    camera_up: [f32; 4],
    camera_fwd: [f32; 4],
    fog_shaft: [f32; 4],
    misc: [f32; 4],
}
const _: () = assert!(std::mem::size_of::<ShaftMarchUniforms>() == 96);

/// Upsample-composite uniforms (VOLUMETRIC_LIGHT_DESIGN.md D3). Just the
/// camera near/far the bilateral weight's `linearize_depth` needs.
#[repr(C)]
#[derive(Clone, Copy, bytemuck::Pod, bytemuck::Zeroable)]
struct ShaftCompositeUniforms {
    near_far: [f32; 4],
}
const _: () = assert!(std::mem::size_of::<ShaftCompositeUniforms>() == 16);

impl RenderScene {
    pub fn new() -> Self {
        let mut s = Self {
            inputs: Vec::new(),
            params: Vec::new(),
            num_objects: 0,
            num_lights: 0,
            pipelines: AHashMap::new(),
            depth_stencil: None,
            blend_depth_stencil: None,
            msaa_color: None,
            depth_texture: None,
            depth_width: 0,
            depth_height: 0,
            velocity_msaa: None,
            velocity_width: 0,
            velocity_height: 0,
            prev_model: Vec::new(),
            prev_view_proj: None,
            jitter_frame_index: 0,
            dummy_texture: None,
            sampler: None,
            material_samplers: AHashMap::default(),
            light_buffers: Vec::new(),
            light_frame: 0,
            light_capacity: 0,
            shadow_pipeline: None,
            shadow_depth_stencil: None,
            shadow_maps: std::array::from_fn(|_| None),
            shadow_cache_keys: std::array::from_fn(|_| None),
            shadow_sampler: None,
            dummy_depth: None,
            identity_instance_stub: None,
            shaft_inscatter: None,
            shaft_depth_half: None,
            shaft_half_width: 0,
            shaft_half_height: 0,
            shaft_depth_internal: None,
            shaft_depth_internal_width: 0,
            shaft_depth_internal_height: 0,
            shaft_downsample_pipeline: None,
            shaft_march_pipeline: None,
            shaft_composite_pipeline: None,
            opaque_scene_color: None,
            opaque_scene_color_width: 0,
            opaque_scene_color_height: 0,
            opaque_scene_color_format: manifold_gpu::GpuTextureFormat::Rgba16Float,
            opaque_depth_snapshot: None,
            opaque_depth_snapshot_width: 0,
            opaque_depth_snapshot_height: 0,
            prefiltered_specular: None,
            irradiance_map: None,
            brdf_lut: None,
            brdf_lut_built: false,
            ibl_cache_key: None,
            ibl_prefilter_pipeline: None,
            ibl_irradiance_pipeline: None,
            ibl_brdf_lut_pipeline: None,
            object_port_names: Vec::new(),
            light_port_names: Vec::new(),
        };
        s.rebuild(DEFAULT_OBJECTS, DEFAULT_LIGHTS);
        s
    }

    /// (Re)build the input port list AND the parameter list for
    /// `objects` objects / `lights` lights (each clamped to its cap).
    fn rebuild(&mut self, objects: u32, lights: u32) {
        let objects = objects.clamp(1, OBJECT_SAFETY_MAX);
        let lights = lights.clamp(0, LIGHT_SLIDER_MAX);
        let n_obj = objects as usize;
        let n_lights = lights as usize;

        let mut inputs = Vec::with_capacity(3 + n_lights + n_obj * 9);
        inputs.push(NodePort {
            name: std::borrow::Cow::Borrowed("camera"),
            ty: PortType::Camera,
            kind: PortKind::Input,
            required: true,
        });
        inputs.push(NodePort {
            name: std::borrow::Cow::Borrowed("envmap"),
            ty: PortType::Texture2D,
            kind: PortKind::Input,
            required: false,
        });
        // Optional scene-wide atmosphere (P3). Unwired = fog off,
        // byte-identical to no atmosphere.
        inputs.push(NodePort {
            name: std::borrow::Cow::Borrowed("atmosphere"),
            ty: PortType::Atmosphere,
            kind: PortKind::Input,
            required: false,
        });
        for i in 0..n_lights {
            inputs.push(NodePort {
                name: std::borrow::Cow::Owned(format!("light_{i}")),
                ty: PortType::Light,
                kind: PortKind::Input,
                required: false,
            });
        }
        // SCENE_OBJECT_AND_PANEL_V2_DESIGN.md D4/P2: one `object_{i}:
        // Object` port per object, replacing the 21 legacy per-object port
        // families (mesh_i/material_i/17 maps/transform_i/instances_i).
        // `node.scene_object` binds all of that into one `SceneObject`;
        // unwired = skip (no draw, no shadow — D4). Optional, not required:
        // an in-progress edit that hasn't wired every object slot yet must
        // not error the whole scene, it just skips that object.
        for i in 0..n_obj {
            inputs.push(NodePort {
                name: std::borrow::Cow::Owned(format!("object_{i}")),
                ty: PortType::Object,
                kind: PortKind::Input,
                required: false,
            });
        }

        let params = vec![
            ParamDef {
                name: std::borrow::Cow::Borrowed("objects"),
                label: "Objects",
                ty: ParamType::Int,
                default: ParamValue::Float(DEFAULT_OBJECTS as f32),
                range: Some((1.0, OBJECT_SAFETY_MAX as f32)),
                enum_values: &[],
            },
            ParamDef {
                name: std::borrow::Cow::Borrowed("lights"),
                label: "Lights",
                ty: ParamType::Int,
                default: ParamValue::Float(DEFAULT_LIGHTS as f32),
                range: Some((0.0, LIGHT_SLIDER_MAX as f32)),
                enum_values: &[],
            },
            // RAYTRACING_DESIGN.md D14 (W0): per-scene RT toggle. Default
            // off — an untouched scene is byte-identical to before this
            // param existed (`force_consumed_outputs` returns empty unless
            // this is explicitly `true`). P1 wires the real scene-level
            // toggle (EditingService + serialization) through to this same
            // param; W0 only builds the render-pass side of the contract.
            ParamDef {
                name: std::borrow::Cow::Borrowed("rt_enabled"),
                label: "RT Enabled",
                ty: ParamType::Bool,
                default: ParamValue::Bool(false),
                range: None,
                enum_values: &[],
            },
            // RAYTRACING_DESIGN.md §5.2 P4: per-scene MetalFX Temporal
            // quality-mode toggle. Default off — an untouched scene is
            // byte-identical to before this param existed (no jitter
            // applied to `view_proj`, `force_consumed_outputs` unaffected
            // unless this is explicitly `true`). Wiring this into an
            // actual reduced-res-render + upscale pass through
            // `crate::metalfx_temporal_upscaler::MetalFxTemporalUpscaler`
            // is follow-on work (this P4 lane builds the render-pass
            // CONTRACT — jitter + forced G-buffer outputs — the same
            // staged scope W0 used for `rt_enabled`).
            ParamDef {
                name: std::borrow::Cow::Borrowed("temporal_upscale"),
                label: "Temporal Upscale",
                ty: ParamType::Bool,
                default: ParamValue::Bool(false),
                range: None,
                enum_values: &[],
            },
        ];
        // Per-object TRS is no longer a param loop here — `transform_{i}`
        // (added above) carries it as a `Transform` port fed by a
        // `node.transform_3d` atom (SCENE_BUILD_AND_GROUP_PARAMS_DESIGN.md
        // §2 D3). Do NOT re-add per-object params as an unwired fallback —
        // that is the forbidden parallel-old-path shape D3 names explicitly.

        self.inputs = inputs;
        self.params = params;
        self.num_objects = objects;
        self.num_lights = lights;
        // GBUFFER_DESIGN.md §2 D5 (P2): an object-count change may reassign
        // what slot `n` means, so any previous-frame history is discarded
        // here rather than risked — the next `evaluate()` after a rebuild
        // treats every object as brand new (first-frame zero velocity),
        // exactly the same "no history yet" case a freshly-created node
        // starts in.
        self.prev_model = vec![None; n_obj];
        self.prev_view_proj = None;

        // RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md P4 (R5): format every
        // port name exactly once, here, at rebuild time (only reached on an
        // `objects`/`lights` param change — never per frame). `evaluate()`
        // indexes these by object/light number instead of calling `format!`
        // itself.
        self.object_port_names =
            (0..n_obj).map(|i| format!("object_{i}").into_boxed_str()).collect();
        self.light_port_names =
            (0..n_lights).map(|i| format!("light_{i}").into_boxed_str()).collect();
    }

    /// Ensure the memoryless MSAA color + depth targets match the render
    /// target size. Both are `MSAA_SAMPLES`x multisample, tile-resident
    /// (never leave the GPU); the color resolves out at pass end.
    fn ensure_msaa_targets(&mut self, device: &manifold_gpu::GpuDevice, width: u32, height: u32) {
        if self.depth_width == width
            && self.depth_height == height
            && self.depth_texture.is_some()
            && self.msaa_color.is_some()
        {
            return;
        }
        self.msaa_color = Some(device.create_texture_msaa_memoryless(
            width,
            height,
            manifold_gpu::GpuTextureFormat::Rgba16Float,
            MSAA_SAMPLES,
            "node.render_scene msaa color",
        ));
        self.depth_texture = Some(device.create_texture_msaa_memoryless(
            width,
            height,
            manifold_gpu::GpuTextureFormat::Depth32Float,
            MSAA_SAMPLES,
            "node.render_scene msaa depth",
        ));
        self.depth_width = width;
        self.depth_height = height;
    }

    /// Ensure the memoryless MSAA `Rg16Float` velocity aux-MRT target
    /// matches the render target size (GBUFFER_DESIGN.md §2 D5, P2). Called
    /// ONLY when `evaluate` finds `velocity` wired this frame (D1 lazy
    /// rule) — an unwired scene never calls this, so it costs nothing.
    fn ensure_velocity_msaa_target(
        &mut self,
        device: &manifold_gpu::GpuDevice,
        width: u32,
        height: u32,
    ) {
        if self.velocity_width == width
            && self.velocity_height == height
            && self.velocity_msaa.is_some()
        {
            return;
        }
        self.velocity_msaa = Some(device.create_texture_msaa_memoryless(
            width,
            height,
            manifold_gpu::GpuTextureFormat::Rg16Float,
            MSAA_SAMPLES,
            "node.render_scene msaa velocity",
        ));
        self.velocity_width = width;
        self.velocity_height = height;
    }

    fn ensure_sampler(&mut self, device: &manifold_gpu::GpuDevice) {
        if self.sampler.is_none() {
            self.sampler = Some(device.create_sampler(&manifold_gpu::GpuSamplerDesc {
                mag_filter: manifold_gpu::GpuFilterMode::Linear,
                min_filter: manifold_gpu::GpuFilterMode::Linear,
                mip_filter: manifold_gpu::GpuFilterMode::Linear,
                address_mode_u: manifold_gpu::GpuAddressMode::Repeat,
                address_mode_v: manifold_gpu::GpuAddressMode::ClampToEdge,
                address_mode_w: manifold_gpu::GpuAddressMode::ClampToEdge,
                compare: None,
                ..Default::default()
            }));
        }
    }

    /// GLB_XFAIL_BURNDOWN_DESIGN.md D3: pack a `MapSamplerDesc` into a small
    /// dense key for the `material_samplers` cache. `GpuAddressMode`/
    /// `GpuFilterMode` don't derive `Hash` (foreign types in `manifold-gpu`,
    /// not worth adding a derive there for one call site) — a hand-rolled
    /// 4-variant/2-variant discriminant packs into 3 bits, well inside a u32.
    fn sampler_cache_key(desc: MapSamplerDesc) -> u32 {
        fn addr_code(a: manifold_gpu::GpuAddressMode) -> u32 {
            match a {
                manifold_gpu::GpuAddressMode::ClampToEdge => 0,
                manifold_gpu::GpuAddressMode::Repeat => 1,
                manifold_gpu::GpuAddressMode::MirrorRepeat => 2,
                manifold_gpu::GpuAddressMode::ClampToZero => 3,
            }
        }
        fn filter_code(f: manifold_gpu::GpuFilterMode) -> u32 {
            match f {
                manifold_gpu::GpuFilterMode::Nearest => 0,
                manifold_gpu::GpuFilterMode::Linear => 1,
            }
        }
        addr_code(desc.wrap_u)
            | (addr_code(desc.wrap_v) << 2)
            | (filter_code(desc.mag_filter) << 4)
            | (filter_code(desc.min_filter) << 5)
    }

    /// GLB_XFAIL_BURNDOWN_DESIGN.md D3: ensure a cached sampler exists for
    /// `desc`, creating it on first sight. Replaces the single hardcoded
    /// REPEAT material-map sampler (binding 22, landed `85b5bb9d`) — but
    /// `MapSamplerDesc::default()` (an unwired map, or a glTF texture with
    /// no explicit `sampler` index) still resolves to REPEAT+linear, so
    /// every asset that never sets these fields (every pre-D3 passing
    /// asset, plus DamagedHelmet's UV range [1.0, 2.0] that motivated the
    /// original fix) gets byte-identical sampler behavior to before this
    /// phase — the striped-helmet regression `85b5bb9d` fixed stays fixed.
    fn ensure_material_sampler(&mut self, device: &manifold_gpu::GpuDevice, desc: MapSamplerDesc) {
        let key = Self::sampler_cache_key(desc);
        self.material_samplers.entry(key).or_insert_with(|| {
            device.create_sampler(&manifold_gpu::GpuSamplerDesc {
                mag_filter: desc.mag_filter,
                min_filter: desc.min_filter,
                mip_filter: manifold_gpu::GpuFilterMode::Linear,
                address_mode_u: desc.wrap_u,
                address_mode_v: desc.wrap_v,
                address_mode_w: manifold_gpu::GpuAddressMode::Repeat,
                compare: None,
                // Anisotropic filtering (D7, GLB_CONFORMANCE G-P3): glancing-angle
                // minification on grazing surfaces (floors, the AMG's paint) stays
                // sharp instead of over-blurring. Material samplers only — every
                // other sampler in this file keeps the field's default (1).
                max_anisotropy: 8,
            })
        });
    }

    fn ensure_dummy_texture(&mut self, device: &manifold_gpu::GpuDevice) {
        if self.dummy_texture.is_none() {
            self.dummy_texture = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
                width: 1,
                height: 1,
                depth: 1,
                format: manifold_gpu::GpuTextureFormat::Rgba16Float,
                dimension: manifold_gpu::GpuTextureDimension::D2,
                usage: manifold_gpu::GpuTextureUsage::SHADER_READ,
                label: "node.render_scene dummy",
                mip_levels: 1,
            }));
        }
    }

    /// Ensure the shader-ABI binding stubs the main pass ALWAYS needs: the
    /// PCF comparison sampler (`@binding(14)`) and the 1×1 dummy depth
    /// texture bound to non-caster shadow-map slots. Cheap; called every
    /// frame regardless of whether any light casts. The depth-only shadow
    /// *pipeline* and per-caster maps are NOT created here — that is real
    /// shadow work, gated on there actually being a caster
    /// ([`Self::ensure_shadow_pass`]), so an unwired scene pays nothing.
    fn ensure_shadow_binding_stubs(&mut self, device: &manifold_gpu::GpuDevice) {
        if self.shadow_sampler.is_none() {
            // Comparison sampler: linear filtering gives hardware 2×2 PCF per
            // tap, clamp addressing so off-map samples read the border depth.
            self.shadow_sampler = Some(device.create_sampler(&manifold_gpu::GpuSamplerDesc {
                mag_filter: manifold_gpu::GpuFilterMode::Linear,
                min_filter: manifold_gpu::GpuFilterMode::Linear,
                mip_filter: manifold_gpu::GpuFilterMode::Linear,
                address_mode_u: manifold_gpu::GpuAddressMode::ClampToEdge,
                address_mode_v: manifold_gpu::GpuAddressMode::ClampToEdge,
                address_mode_w: manifold_gpu::GpuAddressMode::ClampToEdge,
                compare: Some(manifold_gpu::GpuCompareFunction::Less),
                ..Default::default()
            }));
        }
        if self.dummy_depth.is_none() {
            // Bound to unused/non-caster shadow-map slots. Never sampled (the
            // shader returns "lit" before sampling a non-caster slot), but
            // Metal requires every declared binding to be a valid texture.
            // RENDER_TARGET | SHADER_READ, like the real maps, so no depth
            // format needs a render-target-only exception (AGX 0x78 guard).
            self.dummy_depth = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
                width: 1,
                height: 1,
                depth: 1,
                format: manifold_gpu::GpuTextureFormat::Depth32Float,
                dimension: manifold_gpu::GpuTextureDimension::D2,
                usage: manifold_gpu::GpuTextureUsage::RENDER_TARGET
                    | manifold_gpu::GpuTextureUsage::SHADER_READ,
                label: "node.render_scene dummy shadow",
                mip_levels: 1,
            }));
        }
    }

    /// Ensure the depth-only shadow pipeline + its depth-stencil state exist.
    /// Called ONLY when at least one caster is present — compiling the shadow
    /// shader is real work an unwired scene must not pay.
    fn ensure_shadow_pass(&mut self, device: &manifold_gpu::GpuDevice) {
        if self.shadow_pipeline.is_none() {
            self.shadow_pipeline = Some(device.create_render_pipeline_depth_only(
                include_str!("shaders/shadow_depth.wgsl"),
                "vs_main",
                "fs_shadow",
                manifold_gpu::GpuTextureFormat::Depth32Float,
                "node.render_scene shadow depth",
            ));
        }
        if self.shadow_depth_stencil.is_none() {
            self.shadow_depth_stencil = Some(device.create_depth_stencil_state(
                &manifold_gpu::GpuDepthStencilDesc {
                    compare: manifold_gpu::GpuCompareFunction::Less,
                    write_enabled: true,
                },
            ));
        }
    }

    /// Ensure shadow map `slot` is a private `Depth32Float` of `resolution`²,
    /// recreating it if the caster's requested resolution changed.
    /// `RENDER_TARGET | SHADER_READ`: rendered as a depth target, then sampled
    /// as a shadow map — both usages at creation (AGX 0x78 guard).
    fn ensure_shadow_map(&mut self, device: &manifold_gpu::GpuDevice, slot: usize, resolution: u32) {
        let res = resolution.clamp(256, 4096);
        let needs = match &self.shadow_maps[slot] {
            Some((cached, _)) => *cached != res,
            None => true,
        };
        if needs {
            let tex = device.create_texture(&manifold_gpu::GpuTextureDesc {
                width: res,
                height: res,
                depth: 1,
                format: manifold_gpu::GpuTextureFormat::Depth32Float,
                dimension: manifold_gpu::GpuTextureDimension::D2,
                usage: manifold_gpu::GpuTextureUsage::RENDER_TARGET
                    | manifold_gpu::GpuTextureUsage::SHADER_READ,
                label: "node.render_scene shadow map",
                mip_levels: 1,
            });
            self.shadow_maps[slot] = Some((res, tex));
        }
    }

    /// VOLUMETRIC_LIGHT_DESIGN.md D3 (P2): ensure the half-res
    /// `shaft_inscatter` (`Rgba16Float`) and `shaft_depth_half` (`R32Float`)
    /// textures match `half_w x half_h`, recreating on resize. Same
    /// `ensure_shadow_map` lazy pattern — called ONLY when [`wants_shafts`]
    /// is true this frame.
    fn ensure_shaft_half_res(&mut self, device: &manifold_gpu::GpuDevice, half_w: u32, half_h: u32) {
        if self.shaft_half_width == half_w
            && self.shaft_half_height == half_h
            && self.shaft_inscatter.is_some()
            && self.shaft_depth_half.is_some()
        {
            return;
        }
        self.shaft_inscatter = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
            width: half_w,
            height: half_h,
            depth: 1,
            format: manifold_gpu::GpuTextureFormat::Rgba16Float,
            dimension: manifold_gpu::GpuTextureDimension::D2,
            usage: manifold_gpu::GpuTextureUsage::SHADER_READ
                | manifold_gpu::GpuTextureUsage::SHADER_WRITE,
            label: "node.render_scene shaft inscatter",
            mip_levels: 1,
        }));
        self.shaft_depth_half = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
            width: half_w,
            height: half_h,
            depth: 1,
            format: manifold_gpu::GpuTextureFormat::R32Float,
            dimension: manifold_gpu::GpuTextureDimension::D2,
            usage: manifold_gpu::GpuTextureUsage::SHADER_READ
                | manifold_gpu::GpuTextureUsage::SHADER_WRITE,
            label: "node.render_scene shaft depth half",
            mip_levels: 1,
        }));
        self.shaft_half_width = half_w;
        self.shaft_half_height = half_h;
    }

    /// VOLUMETRIC_LIGHT_DESIGN.md D3 (P2): ensure the full-res internal
    /// depth-resolve target used ONLY when shafts are on and the graph's
    /// `depth` output is unwired this frame — "shafts-on forces the
    /// internal Sample0 depth resolve even when `depth` is unwired" (D3).
    /// `RENDER_TARGET` because it is a resolve target of the MSAA depth
    /// pass; `SHADER_READ` because the downsample kernel reads it.
    fn ensure_shaft_depth_internal(&mut self, device: &manifold_gpu::GpuDevice, width: u32, height: u32) {
        if self.shaft_depth_internal_width == width
            && self.shaft_depth_internal_height == height
            && self.shaft_depth_internal.is_some()
        {
            return;
        }
        self.shaft_depth_internal = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
            width,
            height,
            depth: 1,
            format: manifold_gpu::GpuTextureFormat::R32Float,
            dimension: manifold_gpu::GpuTextureDimension::D2,
            usage: manifold_gpu::GpuTextureUsage::RENDER_TARGET
                | manifold_gpu::GpuTextureUsage::SHADER_READ,
            label: "node.render_scene shaft depth internal",
            mip_levels: 1,
        }));
        self.shaft_depth_internal_width = width;
        self.shaft_depth_internal_height = height;
    }

    /// GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a/E2b: (re)allocate the opaque-
    /// scene color snapshot when size or format changed. `SHADER_READ` only
    /// — it is populated by a blit (`copy_texture_to_texture`, level 0 only)
    /// then mip-generated (`GpuEncoder::generate_mipmaps`, the same hardware
    /// blit-encoder path `node.gltf_texture_source` uses for its material
    /// maps, F-P6 precedent) — never a render pass, so it needs no
    /// `RENDER_TARGET` bit. `format` mirrors whatever the graph's own
    /// `color` output texture is using this frame (read live from
    /// `target.format` at the call site) so the blit's mandatory
    /// same-format assert can never trip on a future output-format change.
    /// E2b: full mip chain (`max_mip_levels`) so `fs_pbr`'s roughness-driven
    /// refraction blur has levels to sample — level 0 alone (E2a) only
    /// proved the pass seam, not the blur.
    fn ensure_opaque_scene_color(
        &mut self,
        device: &manifold_gpu::GpuDevice,
        width: u32,
        height: u32,
        format: manifold_gpu::GpuTextureFormat,
    ) {
        if self.opaque_scene_color_width == width
            && self.opaque_scene_color_height == height
            && self.opaque_scene_color_format == format
            && self.opaque_scene_color.is_some()
        {
            return;
        }
        self.opaque_scene_color = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
            width,
            height,
            depth: 1,
            format,
            dimension: manifold_gpu::GpuTextureDimension::D2,
            usage: manifold_gpu::GpuTextureUsage::SHADER_READ,
            label: "node.render_scene opaque scene color (E2b transmission snapshot)",
            mip_levels: manifold_gpu::GpuTextureDesc::max_mip_levels(width, height),
        }));
        self.opaque_scene_color_width = width;
        self.opaque_scene_color_height = height;
        self.opaque_scene_color_format = format;
    }

    /// E2a: (re)allocate the real single-sample `Depth32Float` opaque-depth
    /// snapshot Pass B depth-tests against. `RENDER_TARGET` only — it is
    /// written by a depth-only render pass and never sampled (E2a proves
    /// only the depth-test plumbing; nothing reads this texture in a
    /// shader this phase).
    fn ensure_opaque_depth_snapshot(&mut self, device: &manifold_gpu::GpuDevice, width: u32, height: u32) {
        if self.opaque_depth_snapshot_width == width
            && self.opaque_depth_snapshot_height == height
            && self.opaque_depth_snapshot.is_some()
        {
            return;
        }
        self.opaque_depth_snapshot = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
            width,
            height,
            depth: 1,
            format: manifold_gpu::GpuTextureFormat::Depth32Float,
            dimension: manifold_gpu::GpuTextureDimension::D2,
            usage: manifold_gpu::GpuTextureUsage::RENDER_TARGET,
            label: "node.render_scene opaque depth snapshot (E2a)",
            mip_levels: 1,
        }));
        self.opaque_depth_snapshot_width = width;
        self.opaque_depth_snapshot_height = height;
    }

    /// VOLUMETRIC_LIGHT_DESIGN.md D2/D3 (P2): ensure the three internal
    /// shaft pipelines exist. Compiled once, straight from `include_str!`
    /// WGSL — each file forks its own `linearize_depth` copy (the
    /// established "forked, not shared" convention this codebase's other
    /// hand-authored consumers already use, e.g. ssao_from_depth.wgsl), so
    /// no concatenation is needed and each file validates standalone under
    /// `tests/wgsl_validation.rs`'s auto-discovery. Hand-written pipelines,
    /// NOT the `primitive!` codegen path (these are internal `render_scene`
    /// passes, not graph atoms; §2.5 audit).
    fn ensure_shaft_pipelines(&mut self, device: &manifold_gpu::GpuDevice) {
        if self.shaft_downsample_pipeline.is_none() {
            self.shaft_downsample_pipeline = Some(device.create_compute_pipeline(
                include_str!("shaders/shaft_depth_downsample.wgsl"),
                "cs_main",
                "node.render_scene shaft downsample",
            ));
        }
        if self.shaft_march_pipeline.is_none() {
            self.shaft_march_pipeline = Some(device.create_compute_pipeline(
                include_str!("shaders/shaft_march.wgsl"),
                "cs_main",
                "node.render_scene shaft march",
            ));
        }
        if self.shaft_composite_pipeline.is_none() {
            let blend = manifold_gpu::GpuBlendState {
                src_factor: manifold_gpu::GpuBlendFactor::One,
                dst_factor: manifold_gpu::GpuBlendFactor::One,
                operation: manifold_gpu::GpuBlendOp::Add,
                // Alpha untouched (D3): src_alpha=Zero, dst_alpha=One means
                // `dst.a * 1 + 0 = dst.a` regardless of what the fragment
                // shader writes to its own alpha channel.
                src_alpha_factor: manifold_gpu::GpuBlendFactor::Zero,
                dst_alpha_factor: manifold_gpu::GpuBlendFactor::One,
                alpha_operation: manifold_gpu::GpuBlendOp::Add,
            };
            self.shaft_composite_pipeline = Some(device.create_render_pipeline(
                include_str!("shaders/shaft_composite.wgsl"),
                "vs_main",
                "fs_main",
                manifold_gpu::GpuTextureFormat::Rgba16Float,
                Some(blend),
                "node.render_scene shaft composite",
            ));
        }
    }

    /// Ensure the cached 1-entry identity `InstanceTransform` stub bound to
    /// any object's `instances_n` when that port is unwired (D11). Created
    /// once; cheap, called every frame like the shadow ABI stubs.
    fn ensure_identity_instance_stub(&mut self, device: &manifold_gpu::GpuDevice) {
        if self.identity_instance_stub.is_none() {
            let stub = InstanceTransform {
                pos_scale: [0.0, 0.0, 0.0, 1.0],
                rot_pad: [0.0, 0.0, 0.0, 0.0],
            };
            let buf =
                device.create_buffer_shared(std::mem::size_of::<InstanceTransform>() as u64);
            unsafe {
                buf.write(0, bytemuck::bytes_of(&stub));
            }
            self.identity_instance_stub = Some(buf);
        }
    }

    /// IMPORT_FIDELITY_DESIGN.md D2/F-P1: ensure the three split-sum IBL
    /// GPU resources exist — the prefiltered specular mip chain, the
    /// diffuse irradiance map, and the BRDF LUT — plus their three compute
    /// pipelines. All three are FIXED size (never resized, so this only
    /// ever allocates once); called every frame like the other ABI-stub
    /// ensures (`ensure_dummy_texture`, `ensure_shadow_binding_stubs`) so
    /// `@binding(16..18)` always has something valid bound regardless of
    /// whether `envmap` is wired or any object is PBR.
    fn ensure_ibl_resources(&mut self, device: &manifold_gpu::GpuDevice) {
        if self.prefiltered_specular.is_none() {
            self.prefiltered_specular = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
                width: PREFILTER_BASE_WIDTH,
                height: PREFILTER_BASE_HEIGHT,
                depth: 1,
                format: manifold_gpu::GpuTextureFormat::Rgba16Float,
                dimension: manifold_gpu::GpuTextureDimension::D2,
                usage: manifold_gpu::GpuTextureUsage::SHADER_READ
                    | manifold_gpu::GpuTextureUsage::SHADER_WRITE,
                label: "node.render_scene ibl prefiltered specular",
                mip_levels: PREFILTER_MIP_COUNT,
            }));
        }
        if self.irradiance_map.is_none() {
            self.irradiance_map = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
                width: IRRADIANCE_WIDTH,
                height: IRRADIANCE_HEIGHT,
                depth: 1,
                format: manifold_gpu::GpuTextureFormat::Rgba16Float,
                dimension: manifold_gpu::GpuTextureDimension::D2,
                usage: manifold_gpu::GpuTextureUsage::SHADER_READ
                    | manifold_gpu::GpuTextureUsage::SHADER_WRITE,
                label: "node.render_scene ibl irradiance",
                mip_levels: 1,
            }));
        }
        if self.brdf_lut.is_none() {
            self.brdf_lut = Some(device.create_texture(&manifold_gpu::GpuTextureDesc {
                width: BRDF_LUT_SIZE,
                height: BRDF_LUT_SIZE,
                depth: 1,
                format: manifold_gpu::GpuTextureFormat::Rg16Float,
                dimension: manifold_gpu::GpuTextureDimension::D2,
                usage: manifold_gpu::GpuTextureUsage::SHADER_READ
                    | manifold_gpu::GpuTextureUsage::SHADER_WRITE,
                label: "node.render_scene ibl brdf lut",
                mip_levels: 1,
            }));
        }
        if self.ibl_prefilter_pipeline.is_none() {
            self.ibl_prefilter_pipeline = Some(device.create_compute_pipeline(
                concat!(
                    include_str!("shaders/pbr_brdf.wgsl"),
                    include_str!("shaders/ibl_prefilter_specular.wgsl"),
                ),
                "cs_main",
                "node.render_scene ibl prefilter",
            ));
        }
        if self.ibl_irradiance_pipeline.is_none() {
            self.ibl_irradiance_pipeline = Some(device.create_compute_pipeline(
                concat!(
                    include_str!("shaders/pbr_brdf.wgsl"),
                    include_str!("shaders/ibl_irradiance.wgsl"),
                ),
                "cs_main",
                "node.render_scene ibl irradiance",
            ));
        }
        if self.ibl_brdf_lut_pipeline.is_none() {
            self.ibl_brdf_lut_pipeline = Some(device.create_compute_pipeline(
                concat!(
                    include_str!("shaders/pbr_brdf.wgsl"),
                    include_str!("shaders/ibl_brdf_lut.wgsl"),
                ),
                "cs_main",
                "node.render_scene ibl brdf lut",
            ));
        }
    }

    /// IMPORT_FIDELITY_DESIGN.md D2/F-P1: run the split-sum IBL convolution
    /// passes. Call ONLY after [`Self::ensure_ibl_resources`].
    ///
    /// The BRDF LUT is envmap-independent (view/roughness-only) — built
    /// EXACTLY ONCE per device, gated by `brdf_lut_built`, a genuine cache
    /// hit every frame after the first (see the `ibl_brdf_lut_builds_once`
    /// gpu-proofs test).
    ///
    /// **Superseded by RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md D7 (P3):**
    /// the prefiltered specular chain and irradiance map used to be
    /// re-convolved on EVERY call this function was invoked with `envmap =
    /// Some(_)` — this section used to warn that a pointer/size-identity
    /// skip would silently serve outdated convolution output, because
    /// `bake_equirect_envmap::run()` mutated its SAME persistent output
    /// texture in place every frame regardless of whether its params
    /// changed, so identity alone could never tell "unchanged" from
    /// "rewritten with different content." That hazard is closed now, at
    /// the root: `bake_equirect_envmap` (and `hdri_source`)
    /// no longer rewrite unconditionally — each skips its own dispatch and
    /// calls `ctx.mark_outputs_unchanged()` only when its full param set
    /// (or decoded file) AND its output texture's physical identity are
    /// both unchanged since the last frame it actually wrote (P3's producer
    /// gate, landed and parity-tested before this consumer gate was
    /// enabled — D7's load-bearing ordering). That declaration is what
    /// bumps (or doesn't bump) the envmap slot's write generation (D5): a
    /// truthful "unchanged" is the ONLY way the generation can fail to
    /// bump, and a false declaration is a per-node-tested property (I3),
    /// not this call site's concern. So convolution below is skipped only
    /// when `ibl_cache_key` — a hash of (envmap generation, envmap texture
    /// identity, executor rebuild epoch) — matches this frame's freshly
    /// computed key; any mismatch (including first use, an
    /// unwired-to-wired transition, or the D7 sun-coherence animated-envmap
    /// gesture actually changing the bake) falls through to a real
    /// re-convolution (I2: never served on a partial match). The identity
    /// term stays in the key as the same belt-and-suspenders precedent
    /// `shadow_cache_keys` uses, and the rebuild-epoch term is required by
    /// `NodeInputs::slot_generation`'s own doc comment (never compare a
    /// generation number alone across executor lifetimes).
    fn run_ibl_convolution(
        &mut self,
        gpu: &mut crate::gpu_encoder::GpuEncoder<'_>,
        sampler: &manifold_gpu::GpuSampler,
        envmap: Option<&manifold_gpu::GpuTexture>,
        envmap_generation: Option<u64>,
        rebuild_epoch: u64,
    ) {
        if !self.brdf_lut_built {
            let lut = self.brdf_lut.as_ref().expect("ensured");
            let pipeline = self.ibl_brdf_lut_pipeline.as_ref().expect("ensured");
            let uniforms = LutUniforms {
                width: BRDF_LUT_SIZE,
                height: BRDF_LUT_SIZE,
                _pad0: 0.0,
                _pad1: 0.0,
            };
            gpu.native_enc.dispatch_compute(
                pipeline,
                &[
                    GpuBinding::Bytes {
                        binding: 0,
                        data: bytemuck::bytes_of(&uniforms),
                    },
                    GpuBinding::Texture { binding: 1, texture: lut },
                ],
                [BRDF_LUT_SIZE.div_ceil(16), BRDF_LUT_SIZE.div_ceil(16), 1],
                "node.render_scene ibl brdf lut",
            );
            self.brdf_lut_built = true;
        }

        let Some(envmap) = envmap else {
            // Unwired ⇒ next wire-up must re-convolve unconditionally, per
            // I2 (never serve a stale key across an unwired gap).
            self.ibl_cache_key = None;
            return;
        };

        use std::hash::{Hash, Hasher};
        let mut hasher = ahash::AHasher::default();
        envmap_generation.hash(&mut hasher);
        hasher.write_usize(envmap.identity_key());
        hasher.write_u64(rebuild_epoch);
        let ibl_key = hasher.finish();
        if self.ibl_cache_key == Some(ibl_key) {
            // I2: cache hit — the persisted prefiltered-specular/irradiance
            // textures already hold this exact envmap's convolution.
            return;
        }
        self.ibl_cache_key = Some(ibl_key);

        let src_width = envmap.width;
        let src_height = envmap.height;

        // Irradiance: one dispatch, whole 32x16 texture.
        {
            let irradiance = self.irradiance_map.as_ref().expect("ensured");
            let pipeline = self.ibl_irradiance_pipeline.as_ref().expect("ensured");
            let uniforms = IrradianceUniforms {
                dst_width: IRRADIANCE_WIDTH,
                dst_height: IRRADIANCE_HEIGHT,
                src_width,
                src_height,
            };
            gpu.native_enc.dispatch_compute(
                pipeline,
                &[
                    GpuBinding::Bytes {
                        binding: 0,
                        data: bytemuck::bytes_of(&uniforms),
                    },
                    GpuBinding::Texture { binding: 1, texture: envmap },
                    GpuBinding::Sampler { binding: 2, sampler },
                    GpuBinding::Texture { binding: 3, texture: irradiance },
                ],
                [IRRADIANCE_WIDTH.div_ceil(8), IRRADIANCE_HEIGHT.div_ceil(8), 1],
                "node.render_scene ibl irradiance",
            );
        }

        // Prefiltered specular chain: one dispatch per mip, each writing
        // into a single-mip VIEW of the chain (`GpuTexture::mip_level_view`
        // — the hardware `generate_mipmaps` box-filter blit cannot express
        // GGX importance convolution, so each level is its own compute
        // pass rather than a derived box-filtered downsample).
        {
            let chain = self.prefiltered_specular.as_ref().expect("ensured");
            let pipeline = self.ibl_prefilter_pipeline.as_ref().expect("ensured");
            for mip in 0..PREFILTER_MIP_COUNT {
                let mip_w = (PREFILTER_BASE_WIDTH >> mip).max(1);
                let mip_h = (PREFILTER_BASE_HEIGHT >> mip).max(1);
                let roughness = mip as f32 / (PREFILTER_MIP_COUNT - 1) as f32;
                let view = chain.mip_level_view(mip, mip_w, mip_h);
                let uniforms = PrefilterUniforms {
                    dst_width: mip_w,
                    dst_height: mip_h,
                    src_width,
                    src_height,
                    roughness,
                    _pad0: 0.0,
                    _pad1: 0.0,
                    _pad2: 0.0,
                };
                gpu.native_enc.dispatch_compute(
                    pipeline,
                    &[
                        GpuBinding::Bytes {
                            binding: 0,
                            data: bytemuck::bytes_of(&uniforms),
                        },
                        GpuBinding::Texture { binding: 1, texture: envmap },
                        GpuBinding::Sampler { binding: 2, sampler },
                        GpuBinding::Texture { binding: 3, texture: &view },
                    ],
                    [mip_w.div_ceil(16), mip_h.div_ceil(16), 1],
                    "node.render_scene ibl prefilter mip",
                );
            }
        }
    }

    /// GBUFFER_DESIGN.md §2 D5 (P2) text-substitution patterns that turn
    /// the base `render_scene.wgsl` (unmodified — the velocity-off
    /// pipeline compiles the file exactly as it ships) into the
    /// EMIT_VELOCITY variant: inject the `FsOut` struct and `VsOut`'s two
    /// extra clip-space fields, compute `clip_now`/`clip_prev` in
    /// `vs_main`, and rewrap every fragment entry's `-> @location(0)
    /// vec4<f32>` return into `-> FsOut` returning
    /// `(color, ndc_now.xy - ndc_prev.xy)`. All four fragment entry points
    /// share byte-identical signature/return text in the base file, so
    /// these two patterns apply once and cover all four — no per-material
    /// duplication, no second shader file (the whole point of the
    /// function-constant mechanism over a shader fork).
    const VELOCITY_SPECIALIZATIONS: &'static [(&'static str, &'static str)] = &[
        (
            "// GBUFFER_FSOUT_VELOCITY_STRUCT",
            "struct FsOut {\n    @location(0) color: vec4<f32>,\n    @location(1) velocity: vec2<f32>,\n};",
        ),
        (
            "// GBUFFER_VSOUT_VELOCITY_FIELDS",
            "@location(3) clip_now: vec4<f32>,\n    @location(4) clip_prev: vec4<f32>,",
        ),
        (
            "// GBUFFER_VS_VELOCITY_BODY",
            "out.clip_now = out.clip_pos;\n    let prev_world = u.prev_model * vec4<f32>(inst_pos, 1.0);\n    out.clip_prev = u.prev_view_proj * prev_world;",
        ),
        ("-> @location(0) vec4<f32> {", "-> FsOut {"),
        (
            "return vec4<f32>(rgb, albedo.a);",
            "return FsOut(vec4<f32>(rgb, albedo.a), (in.clip_now.xy / in.clip_now.w) - (in.clip_prev.xy / in.clip_prev.w));",
        ),
    ];

    /// IMPORT_FIDELITY_DESIGN.md D8: classic straight-alpha "over" blend —
    /// `src_alpha / one_minus_src_alpha` on colour, and the matching
    /// straight-alpha formula on the output alpha channel (`src.a + dst.a *
    /// (1 - src.a)`). Never premultiplied (alpha-standardisation: this
    /// producer is straight-alpha, same convention as the P3 fog pass).
    fn blend_state() -> manifold_gpu::GpuBlendState {
        manifold_gpu::GpuBlendState {
            src_factor: manifold_gpu::GpuBlendFactor::SrcAlpha,
            dst_factor: manifold_gpu::GpuBlendFactor::OneMinusSrcAlpha,
            operation: manifold_gpu::GpuBlendOp::Add,
            src_alpha_factor: manifold_gpu::GpuBlendFactor::One,
            dst_alpha_factor: manifold_gpu::GpuBlendFactor::OneMinusSrcAlpha,
            alpha_operation: manifold_gpu::GpuBlendOp::Add,
        }
    }

    /// IMPORT_FIDELITY_DESIGN.md D8/F-P5: `blend` selects the Blend-material
    /// pipeline variant — real alpha blending, no alpha-to-coverage (which
    /// would double up with the blend state). Same shader source and entry
    /// points as the opaque/mask variant; only the pipeline's fixed-function
    /// blend + alpha-to-coverage state differs (D8: "lighting, IBL, and fog
    /// run identically in both passes").
    fn pipeline_for(
        &mut self,
        device: &manifold_gpu::GpuDevice,
        kind: MaterialKind,
        emit_velocity: bool,
        blend: bool,
    ) -> &manifold_gpu::GpuRenderPipeline {
        let fs_entry = match kind {
            MaterialKind::Unlit => "fs_unlit",
            MaterialKind::Phong => "fs_phong",
            MaterialKind::Pbr => "fs_pbr",
            MaterialKind::Cel => "fs_cel",
        };
        self.pipelines
            .entry((kind, emit_velocity, blend))
            .or_insert_with(|| {
                let blend_state = if blend { Some(Self::blend_state()) } else { None };
                if emit_velocity {
                    device.create_specialized_render_pipeline_depth_msaa(
                        include_str!("shaders/render_scene.wgsl"),
                        "vs_main",
                        fs_entry,
                        Self::VELOCITY_SPECIALIZATIONS,
                        manifold_gpu::GpuTextureFormat::Rgba16Float,
                        manifold_gpu::GpuTextureFormat::Depth32Float,
                        blend_state,
                        MSAA_SAMPLES,
                        !blend,
                        Some(manifold_gpu::GpuTextureFormat::Rg16Float),
                        "node.render_scene.velocity",
                    )
                } else {
                    device.create_render_pipeline_depth_msaa(
                        include_str!("shaders/render_scene.wgsl"),
                        "vs_main",
                        fs_entry,
                        manifold_gpu::GpuTextureFormat::Rgba16Float,
                        manifold_gpu::GpuTextureFormat::Depth32Float,
                        blend_state,
                        MSAA_SAMPLES,
                        // alpha-to-coverage antialiases the cutout `discard`
                        // edge for Opaque/Mask; a Blend pipeline has no
                        // discard and already blends per-fragment alpha, so
                        // it stays off (the two mechanisms would double up).
                        !blend,
                        "node.render_scene",
                    )
                }
            })
    }

    /// BUG-037: compile every `pipeline_for` (`MaterialKind`, `emit_velocity`)
    /// variant into `device`'s shared render-pipeline cache ahead of time.
    /// `pipeline_for` compiles the requested variant lazily on the first draw
    /// that needs it — a real Metal render-pipeline compile (multisampled,
    /// alpha-to-coverage), tens of ms — which is what stalled the content
    /// thread ~37ms on a glTF scene layer's first rendered frame
    /// (`RENDER_TRACE` showed `generators=37.1ms`). The device's pipeline
    /// cache (`manifold-gpu`, keyed by shader hash) is shared across every
    /// `RenderScene` instance and every layer, so warming all 8 fixed
    /// variants once — independent of any specific project or asset — makes
    /// every later `pipeline_for` call, on any layer, a cache hit. Called
    /// from `GeneratorRegistry::prewarm_all` at app startup, the same
    /// sanctioned "compile pipelines ahead of the hot path" mechanism used
    /// for the bundled JSON generator presets.
    pub fn prewarm_pipelines(device: &manifold_gpu::GpuDevice) {
        for kind in [
            MaterialKind::Unlit,
            MaterialKind::Phong,
            MaterialKind::Pbr,
            MaterialKind::Cel,
        ] {
            let fs_entry = match kind {
                MaterialKind::Unlit => "fs_unlit",
                MaterialKind::Phong => "fs_phong",
                MaterialKind::Pbr => "fs_pbr",
                MaterialKind::Cel => "fs_cel",
            };
            device.create_render_pipeline_depth_msaa(
                include_str!("shaders/render_scene.wgsl"),
                "vs_main",
                fs_entry,
                manifold_gpu::GpuTextureFormat::Rgba16Float,
                manifold_gpu::GpuTextureFormat::Depth32Float,
                None,
                MSAA_SAMPLES,
                true,
                "node.render_scene",
            );
            device.create_specialized_render_pipeline_depth_msaa(
                include_str!("shaders/render_scene.wgsl"),
                "vs_main",
                fs_entry,
                Self::VELOCITY_SPECIALIZATIONS,
                manifold_gpu::GpuTextureFormat::Rgba16Float,
                manifold_gpu::GpuTextureFormat::Depth32Float,
                None,
                MSAA_SAMPLES,
                true,
                Some(manifold_gpu::GpuTextureFormat::Rg16Float),
                "node.render_scene.velocity",
            );
            // IMPORT_FIDELITY_DESIGN.md D8/F-P5: the Blend-material pipeline
            // variants (BUG-037 discipline — a live project's first glass
            // draw must be a cache hit, not a first-use compile stall).
            device.create_render_pipeline_depth_msaa(
                include_str!("shaders/render_scene.wgsl"),
                "vs_main",
                fs_entry,
                manifold_gpu::GpuTextureFormat::Rgba16Float,
                manifold_gpu::GpuTextureFormat::Depth32Float,
                Some(Self::blend_state()),
                MSAA_SAMPLES,
                false,
                "node.render_scene.blend",
            );
            device.create_specialized_render_pipeline_depth_msaa(
                include_str!("shaders/render_scene.wgsl"),
                "vs_main",
                fs_entry,
                Self::VELOCITY_SPECIALIZATIONS,
                manifold_gpu::GpuTextureFormat::Rgba16Float,
                manifold_gpu::GpuTextureFormat::Depth32Float,
                Some(Self::blend_state()),
                MSAA_SAMPLES,
                false,
                Some(manifold_gpu::GpuTextureFormat::Rg16Float),
                "node.render_scene.blend.velocity",
            );
        }

        // BUG-found-by-P3-perf-gate (VOLUMETRIC_LIGHT_DESIGN.md P3): the
        // shadow depth-only pipeline (`ensure_shadow_pass`) and the three
        // shaft pipelines (`ensure_shaft_pipelines`) are BOTH asset-
        // independent (fixed shader source, fixed entry points) — the exact
        // BUG-037 shape (a lazy `Option::get_or_insert_with` cache never
        // touched by `GeneratorRegistry::prewarm_all`'s bundled-preset loop,
        // because no bundled preset happens to hit a shadow-casting light or
        // a nonzero shaft_intensity). The P3 content-thread perf gate
        // (`MANIFOLD_RENDER_TRACE=1`, a 4-shadow-casting-light High-quality
        // scene) measured frame 0 at 79.9ms — entirely first-use pipeline
        // compiles, steady state (frames 1-119) stayed under the 20ms
        // budget with no RENDER_TRACE spike at all. Root fix, not a
        // per-scene workaround: warm all four pipelines here so a live
        // project's first shadow-casting/shaft-on frame is a cache hit.
        device.create_render_pipeline_depth_only(
            include_str!("shaders/shadow_depth.wgsl"),
            "vs_main",
            "fs_shadow",
            manifold_gpu::GpuTextureFormat::Depth32Float,
            "node.render_scene shadow depth",
        );
        device.create_compute_pipeline(
            include_str!("shaders/shaft_depth_downsample.wgsl"),
            "cs_main",
            "node.render_scene shaft downsample",
        );
        device.create_compute_pipeline(
            include_str!("shaders/shaft_march.wgsl"),
            "cs_main",
            "node.render_scene shaft march",
        );
        let shaft_composite_blend = manifold_gpu::GpuBlendState {
            src_factor: manifold_gpu::GpuBlendFactor::One,
            dst_factor: manifold_gpu::GpuBlendFactor::One,
            operation: manifold_gpu::GpuBlendOp::Add,
            src_alpha_factor: manifold_gpu::GpuBlendFactor::Zero,
            dst_alpha_factor: manifold_gpu::GpuBlendFactor::One,
            alpha_operation: manifold_gpu::GpuBlendOp::Add,
        };
        device.create_render_pipeline(
            include_str!("shaders/shaft_composite.wgsl"),
            "vs_main",
            "fs_main",
            manifold_gpu::GpuTextureFormat::Rgba16Float,
            Some(shaft_composite_blend),
            "node.render_scene shaft composite",
        );
    }

    /// AI-composition surface metadata.
    pub fn description() -> PrimitiveDescription {
        PrimitiveDescription {
            type_id: RENDER_SCENE_TYPE_ID,
            purpose: "Multi-object 3D scene renderer: draws `objects` separate Array<MeshVertex> meshes (one draw call each, no fixed cap on object count) into ONE shared depth buffer, so nearer objects correctly occlude farther ones — the gap node.render_mesh / node.render_copies can't close (each of those renders into its own private depth buffer). Each object carries its own material_n: Material, an optional base_color_map_n: Texture2D albedo/alpha map, an optional transform_n: Transform (from node.transform_3d; unwired = identity) composed CPU-side into a model matrix, and an optional instances_n: Array(InstanceTransform) — wired, that object draws instance_count = buffer_size / 32 copies (main pass AND every caster's shadow pass), each instance's world transform composed as model_n · T_instance (instance TRS first, the object group's transform_n second, so scattered instances stay glued to their group under a group move); unwired draws once with an identity instance. Instances share the shared depth buffer too, so they correctly occlude and are occluded by every other object in the scene — the gap node.render_copies' private-depth-buffer instancing can't close. When base_color_map_n is wired, the sampled texel modulates material_n's base_color (rgb × rgb) and its alpha drives that material's alpha-cutout discard when alpha_mode is Mask — same resolve_albedo path as node.render_mesh. Each object also carries four optional maps (IMPORT_FIDELITY_DESIGN.md D3): normal_map_n (tangent-space, glTF convention, reconstructed into world space via a screen-space cotangent frame — no vertex tangents needed), mr_map_n (glTF metallic-roughness packing: G=roughness, B=metallic), occlusion_map_n (R channel, darkens ONLY the PBR diffuse IBL term, never direct lighting or specular IBL), and emissive_map_n (sRGB, multiplied by the material's emission factor, added after lighting in every material kind including Unlit). All four are unwired-safe (dummy-bound, byte-identical output). `lights` shared Light inputs light_0..light_{lights-1} (no fixed cap — lights ride a runtime-sized storage buffer) accumulate in the Phong/PBR/Cel shading — each light's direct term is summed, ambient + emission are added once. ONE shared envmap input lights every PBR object in the scene (an environment map is scene-wide, not per-object). Shadows: the first 4 lights (in slot order) whose cast_shadows is set drop real shadow maps onto the scene (PCF-softened per the light's shadow_softness); lights past that cap still illuminate but cast no shadow. Atmosphere/fog (P3) and split-sum IBL (F-P1) apply scene-wide.",
            composition_notes: "objects and lights are reconfigure params: changing either rebuilds the port list (mesh_n/material_n/base_color_map_n/normal_map_n/mr_map_n/occlusion_map_n/emissive_map_n/transform_n/instances_n nonuples, light_0..N); the render node itself carries only `objects`/`lights` as params now, same dynamic-port pattern as node.switch_texture's num_inputs. Wire a node.transform_3d into transform_n to place/animate that object — each of its nine scalar ports (pos/rot/scale) is independently port-shadowed, so an LFO into rot_y spins it live; leaving transform_n unwired renders the object at the origin, unrotated, unit scale. base_color_map_n and the four D3 maps are all optional — leaving any unwired renders that object exactly as before that port existed. instances_n is optional and carries no per-object instance_count param — wire node.scatter_on_mesh (or any Array(InstanceTransform) producer) to draw that many copies; density control lives on the producer (e.g. scatter_on_mesh's port-shadowed count), not on render_scene. A missing mesh_n or material_n, or a PBR material_n with envmap left unwired, is a structured error (ctx.error + magenta clear on `color`), matching render_mesh's no-silent-fallbacks contract. Object 0 clears the shared color+depth target; objects 1..N load onto it — the shared depth buffer resolves occlusion regardless of which object happens to be object 0.",
            examples: &[],
            inputs: &[],
            outputs: &RENDER_SCENE_OUTPUTS,
            params: &[],
        }
    }
}

impl Default for RenderScene {
    fn default() -> Self {
        Self::new()
    }
}

fn cached_type_id() -> &'static EffectNodeType {
    static CELL: std::sync::OnceLock<EffectNodeType> = std::sync::OnceLock::new();
    CELL.get_or_init(|| EffectNodeType::new(RENDER_SCENE_TYPE_ID))
}

/// Build a column-major 4×4 model matrix from TRS params: `model = T *
/// R * S`. Rotation order matches `render_instanced_3d_mesh.wgsl`'s
/// `euler_xyz` (X → Y → Z, i.e. `R = Rz * Ry * Rx`) so render_scene and
/// render_copies agree on what a given `(rot_x, rot_y, rot_z)` means.
/// Non-uniform scale's normal skew is NOT corrected (no
/// inverse-transpose) — v1 limitation, documented on the shader side.
fn model_matrix(pos: [f32; 3], rot: [f32; 3], scale: [f32; 3]) -> [[f32; 4]; 4] {
    let r = euler_xyz_columns(rot);
    [
        [
            r[0][0] * scale[0],
            r[0][1] * scale[0],
            r[0][2] * scale[0],
            0.0,
        ],
        [
            r[1][0] * scale[1],
            r[1][1] * scale[1],
            r[1][2] * scale[1],
            0.0,
        ],
        [
            r[2][0] * scale[2],
            r[2][1] * scale[2],
            r[2][2] * scale[2],
            0.0,
        ],
        [pos[0], pos[1], pos[2], 1.0],
    ]
}

/// Column-major 3×3 rotation matrix for XYZ Euler angles (radians),
/// composed as `Rz * Ry * Rx` — bit-for-bit the same column layout as
/// `render_instanced_3d_mesh.wgsl`'s `euler_xyz`.
fn euler_xyz_columns(rot: [f32; 3]) -> [[f32; 3]; 3] {
    let (cx, sx) = (rot[0].cos(), rot[0].sin());
    let (cy, sy) = (rot[1].cos(), rot[1].sin());
    let (cz, sz) = (rot[2].cos(), rot[2].sin());

    let rx = [[1.0, 0.0, 0.0], [0.0, cx, sx], [0.0, -sx, cx]];
    let ry = [[cy, 0.0, -sy], [0.0, 1.0, 0.0], [sy, 0.0, cy]];
    let rz = [[cz, sz, 0.0], [-sz, cz, 0.0], [0.0, 0.0, 1.0]];

    mat3_mul(mat3_mul(rz, ry), rx)
}

/// Multiply two 3×3 column-major matrices: result = A * B. Mirrors
/// `generators::mesh_pipeline::mat4_mul`'s convention one dimension down.
fn mat3_mul(a: [[f32; 3]; 3], b: [[f32; 3]; 3]) -> [[f32; 3]; 3] {
    let mut out = [[0.0f32; 3]; 3];
    for col in 0..3 {
        for row in 0..3 {
            out[col][row] =
                a[0][row] * b[col][0] + a[1][row] * b[col][1] + a[2][row] * b[col][2];
        }
    }
    out
}

/// Split a folded `[m00, m01, m10, m11, tx, ty]` per-map UV affine
/// (G-P4) into its `vec4` linear part / `vec4` translation part for the
/// uniform.
fn uv_m(t: &[f32; 6]) -> [f32; 4] {
    [t[0], t[1], t[2], t[3]]
}
fn uv_t(t: &[f32; 6]) -> [f32; 4] {
    [t[4], t[5], 0.0, 0.0]
}

#[allow(clippy::too_many_arguments)]
fn build_uniforms(
    view_proj: [[f32; 4]; 4],
    model: [[f32; 4]; 4],
    cam: &Camera,
    material: &Material,
    light_count: f32,
    atmosphere: &Atmosphere,
    prev_view_proj: [[f32; 4]; 4],
    prev_model: [[f32; 4]; 4],
) -> RenderSceneUniforms {
    RenderSceneUniforms {
        view_proj,
        model,
        camera_pos: [cam.pos[0], cam.pos[1], cam.pos[2], 1.0],
        base_color: material.base_color,
        emission: material.emission,
        // GLB_CONFORMANCE_DESIGN.md G-P4/D5: z/w were permanently-zero
        // reserved slots, now ior/specular_factor — see the struct's field
        // doc comment.
        pbr_metallic_roughness: [
            material.metallic,
            material.roughness,
            material.ior,
            material.specular_factor,
        ],
        specular: [
            material.specular_color[0],
            material.specular_color[1],
            material.specular_color[2],
            material.specular_power,
        ],
        pbr_specular_tint: [
            material.specular_tint[0],
            material.specular_tint[1],
            material.specular_tint[2],
            0.0,
        ],
        base_color_uv_m: uv_m(&material.base_color_uv_transform),
        base_color_uv_t: uv_t(&material.base_color_uv_transform),
        normal_uv_m: uv_m(&material.normal_uv_transform),
        normal_uv_t: uv_t(&material.normal_uv_transform),
        mr_uv_m: uv_m(&material.mr_uv_transform),
        mr_uv_t: uv_t(&material.mr_uv_transform),
        occlusion_uv_m: uv_m(&material.occlusion_uv_transform),
        occlusion_uv_t: uv_t(&material.occlusion_uv_transform),
        emissive_uv_m: uv_m(&material.emissive_uv_transform),
        emissive_uv_t: uv_t(&material.emissive_uv_transform),
        cel_params: [
            material.cel_bands as f32,
            material.band_low,
            material.band_high,
            0.0,
        ],
        texture_flags: [0.0, 0.0, 0.0, 0.0],
        texture_flags2: [0.0, 0.0, 0.0, 0.0],
        alpha_params: [
            match material.alpha_mode {
                AlphaMode::Mask => 1.0,
                // IMPORT_FIDELITY_DESIGN.md D8: Blend never discards — its
                // coverage comes from the sorted blend pass's pipeline blend
                // state, not the shader's cutout branch.
                AlphaMode::Opaque | AlphaMode::Blend => 0.0,
            },
            material.alpha_cutoff,
            // GLB_CONFORMANCE_DESIGN.md G-P5/D5: z/w were permanently-zero
            // reserved slots, now clearcoat/clearcoat_roughness — see the
            // struct's field doc comment.
            material.clearcoat,
            material.clearcoat_roughness,
        ],
        // z = exposure_ev (CAMERA_AND_LENS_DESIGN.md §2 D5) — the fragment
        // shaders multiply their final straight rgb by exp2(scene_params.z).
        // Every builder defaults `cam.lens` to `LensParams::PINHOLE`
        // (exposure_ev = 0.0), so an unwired lens is byte-identical (I2/I5).
        scene_params: [light_count, material.ambient, cam.lens.exposure_ev, 0.0],
        fog_color: atmosphere.fog_color,
        fog_params: [atmosphere.fog_density, atmosphere.height_falloff, 0.0, 0.0],
        ambient_tint: atmosphere.ambient_tint,
        shaft_params: [
            atmosphere.shaft_intensity,
            atmosphere.shaft_anisotropy,
            atmosphere.shaft_quality as f32,
            0.0,
        ],
        prev_view_proj,
        prev_model,
        // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E1/D2 — see the struct's field
        // doc comments for the packing rationale.
        sheen_params: [
            material.sheen_color_factor[0],
            material.sheen_color_factor[1],
            material.sheen_color_factor[2],
            material.sheen_roughness_factor,
        ],
        iridescence_params: [
            material.iridescence_factor,
            material.iridescence_ior,
            material.iridescence_thickness_minimum,
            material.iridescence_thickness_maximum,
        ],
        anisotropy_dispersion_params: [
            material.anisotropy_strength,
            material.anisotropy_rotation,
            material.dispersion,
            0.0,
        ],
        transmission_volume_params: [
            material.transmission_factor,
            material.volume_thickness_factor,
            material.volume_attenuation_distance,
            0.0,
        ],
        volume_attenuation_color: [
            material.volume_attenuation_color[0],
            material.volume_attenuation_color[1],
            material.volume_attenuation_color[2],
            0.0,
        ],
    }
}

impl EffectNode for RenderScene {
    fn depth_rule(&self) -> crate::node_graph::depth_rule::DepthRule {
        crate::node_graph::depth_rule::DepthRule::SourceHeight
    }
    fn type_id(&self) -> &EffectNodeType {
        cached_type_id()
    }

    fn boundary_reason(&self) -> Option<crate::node_graph::freeze::classify::BoundaryReason> {
        Some(crate::node_graph::freeze::classify::BoundaryReason::DrawCall)
    }

    fn inputs(&self) -> &[NodeInput] {
        &self.inputs
    }

    fn outputs(&self) -> &[NodeOutput] {
        &RENDER_SCENE_OUTPUTS
    }

    /// A rasterizer's outputs are screen-space: always canvas-sized.
    /// Its texture INPUTS (envmap, per-object base-color maps) are scene
    /// resources whose dims say nothing about the render target — without
    /// this declaration the plan's max-of-input-dims default sized `color`
    /// to the envmap's fixed 1024², so the scene rendered square and was
    /// stretched to canvas by the next node (BUG-140).
    fn output_canvas_scale(
        &self,
        _port: &str,
        _params: &crate::node_graph::effect_node::ParamValues,
    ) -> Option<(u32, u32)> {
        Some((1, 1))
    }

    /// `depth` is `R32Float` (GBUFFER_DESIGN.md §2 D2 — raw device depth,
    /// not linearized: consumers linearize via the shared `depth.wgsl`
    /// helper, D4). `velocity` is `Rg16Float` (§2 D5 — NDC-space `(dx,
    /// dy)` per pixel). `color` uses the backend default.
    /// RAYTRACING_DESIGN.md D14 (W0): `rt_enabled == true` forces `depth`
    /// AND `velocity` into the plan's `consumed_outputs` regardless of
    /// wiring — the per-scene RT toggle's whole effect on the stored
    /// G-buffer. `false` (the default) returns empty, so an ordinary scene
    /// stays exactly on GBUFFER_DESIGN's lazy-by-wire rule (D1),
    /// byte-identical to before this param existed.
    ///
    /// §5.2 P4: `temporal_upscale == true` forces the SAME two outputs —
    /// MetalFX Temporal consumes depth + motion vectors exactly like the
    /// RT shadow-ray pass does, so a temporal-upscale scene needs the
    /// stored G-buffer even when RT itself is off.
    fn force_consumed_outputs(
        &self,
        params: &crate::node_graph::effect_node::ParamValues,
    ) -> &[&'static str] {
        let rt_enabled = matches!(params.get("rt_enabled"), Some(ParamValue::Bool(true)));
        let temporal_upscale =
            matches!(params.get("temporal_upscale"), Some(ParamValue::Bool(true)));
        if rt_enabled || temporal_upscale {
            &["depth", "velocity"]
        } else {
            &[]
        }
    }

    fn output_format(&self, port: &str) -> Option<manifold_gpu::GpuTextureFormat> {
        match port {
            "depth" => Some(manifold_gpu::GpuTextureFormat::R32Float),
            "velocity" => Some(manifold_gpu::GpuTextureFormat::Rg16Float),
            _ => None,
        }
    }

    fn parameters(&self) -> &[ParamDef] {
        &self.params
    }

    fn reconfigure(&mut self, params: &ParamValues) {
        let objects = params
            .get("objects")
            .and_then(|v| v.as_scalar())
            .map(|f| f.round().clamp(1.0, OBJECT_SAFETY_MAX as f32) as u32)
            .unwrap_or(DEFAULT_OBJECTS);
        let lights = params
            .get("lights")
            .and_then(|v| v.as_scalar())
            .map(|f| f.round().clamp(0.0, LIGHT_SLIDER_MAX as f32) as u32)
            .unwrap_or(DEFAULT_LIGHTS);
        if objects != self.num_objects || lights != self.num_lights {
            self.rebuild(objects, lights);
        }
    }

    fn evaluate<'ctx, 'gpu>(&mut self, ctx: &mut EffectNodeContext<'ctx, 'gpu>) {
        let objects = self.num_objects as usize;
        let lights_n = self.num_lights as usize;

        // RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md P4 (R5): built ONCE per
        // frame from this frame's wired ports (`bindings.rs`'s
        // `NodeInputs::build_index`), then every per-light/per-object port
        // lookup below resolves through it in O(1) instead of the
        // `format!` + linear `iter().find` scan §1's CPU row measured as
        // O(objects × wired_ports) ≈ O(objects²). Port NAMES themselves are
        // pre-formatted once in `rebuild()` (`object_port_names` /
        // `light_port_names`) — nothing here calls `format!`.
        let port_index = ctx.inputs.build_index();

        let cam = ctx
            .inputs
            .camera("camera")
            .unwrap_or_else(Camera::default_perspective);
        let envmap_wired = ctx.inputs.texture_2d("envmap");
        // Scene-wide atmosphere (P3). Unwired = Atmosphere::default() = fog
        // density 0 = no fog (the shader's exp fog collapses to identity), so
        // an unwired atmosphere is byte-identical to no atmosphere.
        let atmosphere = ctx.inputs.atmosphere("atmosphere").unwrap_or_default();

        // Build the shared lights buffer from whichever light_N ports are
        // actually wired (unwired slots simply don't contribute — 0 lights
        // is a valid scene state, matched by ambient + emission only). Two
        // vec4s per light. As lights are collected, the first
        // `MAX_SHADOW_CASTING_LIGHTS` of them whose `cast_shadows` is set
        // (in slot order — D4/F2) are recorded as shadow casters; each
        // caster's light-space matrix + PCF params go into the caster table
        // below, and its slot index rides the previously-unused `.w` of the
        // light's colour vec4 (−1.0 = not a caster). Lights beyond the cap
        // still illuminate; they simply carry slot −1 and cast no shadow.
        let mut light_data: Vec<[f32; 4]> = Vec::with_capacity(lights_n * 2);
        let mut light_count: u32 = 0;
        let mut casters: Vec<crate::node_graph::light::Light> =
            Vec::with_capacity(MAX_SHADOW_CASTING_LIGHTS);
        // VOLUMETRIC_LIGHT_DESIGN.md D2 (P3): every wired light (Sun AND
        // Point) contributes to the march — 3-vec4-per-light packing,
        // matching `shaft_march.wgsl`'s `shaft_lights` binding(2) layout
        // field-for-field:
        //   [i*3+0] = Sun: dir-toward-light (.xyz, matches
        //             `Light::light_dir_at`'s Sun case), .w = 0.0 (mode Sun)
        //           = Point: light world position (.xyz), .w = 1.0 (mode Point)
        //   [i*3+1] = premultiplied color.rgb, .w = caster slot (-1 =
        //             unshadowed glow, D2's honest cost)
        //   [i*3+2] = .x = attenuation range (Point only; ignored for Sun)
        // Reuses the SAME `slot` this loop already computed (the caster
        // table below is shared, unfiltered by mode).
        let mut shaft_light_data: Vec<[f32; 4]> = Vec::new();
        let mut shaft_light_count: u32 = 0;
        for i in 0..lights_n {
            let light_slot = port_index.get(self.light_port_names[i].as_ref()).copied();
            if let Some(l) = light_slot.and_then(|s| ctx.inputs.light_slot(s)) {
                let slot: f32 = if l.cast_shadows && casters.len() < MAX_SHADOW_CASTING_LIGHTS {
                    let s = casters.len() as f32;
                    casters.push(l);
                    s
                } else {
                    -1.0
                };
                light_data.push([-l.dir[0], -l.dir[1], -l.dir[2], 1.0]);
                light_data.push([l.color[0], l.color[1], l.color[2], slot]);
                light_count += 1;
                let pos_or_dir = match l.mode {
                    crate::node_graph::light::LightMode::Sun => {
                        [-l.dir[0], -l.dir[1], -l.dir[2], 0.0]
                    }
                    crate::node_graph::light::LightMode::Point => {
                        [l.pos[0], l.pos[1], l.pos[2], 1.0]
                    }
                };
                shaft_light_data.push(pos_or_dir);
                shaft_light_data.push([l.color[0], l.color[1], l.color[2], slot]);
                shaft_light_data.push([l.range, 0.0, 0.0, 0.0]);
                shaft_light_count += 1;
            }
        }
        // D4: `@binding(8)` must ALWAYS be bound (the fragment shaders
        // declare it unconditionally), so a zero-light scene binds one
        // zeroed entry the shader never reads (`light_count == 0`). Skipping
        // the binding on empty is the forbidden silent-fallback shape.
        if light_data.is_empty() {
            light_data.extend([[0.0f32; 4]; 2]);
        }
        // Same D4 always-bind discipline: the march's `shaft_lights`
        // binding must be a valid (non-zero-length) buffer even at 0
        // lights (`shaft_light_count` gates the shader's loop, not the
        // binding's presence). 3 vec4s = one zeroed light-shaped stub.
        if shaft_light_data.is_empty() {
            shaft_light_data.extend([[0.0f32; 4]; 3]);
        }

        // Caster table (`@binding(9)`): `MAX_SHADOW_CASTING_LIGHTS` slots ×
        // `CASTER_VEC4_STRIDE` vec4, zeroed then filled per active caster.
        // Columns 0–3 = shadow_view_proj; vec4 4 = (bias, kernel_half_width,
        // texel_size, light_size). Always fully sized so `@binding(9)` is a
        // fixed bind regardless of caster count (Bytes, copy-at-encode,
        // hazard-free).
        let mut caster_table: Vec<[f32; 4]> =
            vec![[0.0; 4]; MAX_SHADOW_CASTING_LIGHTS * CASTER_VEC4_STRIDE];
        for (slot, l) in casters.iter().enumerate() {
            let vp = l.shadow_view_proj();
            let base = slot * CASTER_VEC4_STRIDE;
            caster_table[base] = vp[0];
            caster_table[base + 1] = vp[1];
            caster_table[base + 2] = vp[2];
            caster_table[base + 3] = vp[3];
            // D12: `Contact` has no fixed kernel width — `kernel_half_width()`
            // returns the sentinel `-1`, which `render_scene.wgsl`'s
            // `shadow_factor` reads as "run the PCSS blocker-search branch,
            // using `light_size` below" instead of the fixed PCF loop.
            let khw = l.shadow_softness.kernel_half_width() as f32;
            let light_size = match l.shadow_softness {
                crate::node_graph::light::ShadowSoftness::Contact { light_size } => light_size,
                _ => 0.0,
            };
            let texel = 1.0 / l.shadow_resolution.clamp(256, 4096) as f32;
            caster_table[base + 4] = [l.shadow_bias, khw, texel, light_size];
        }

        let Some(dims_tex) = ctx.outputs.texture_2d("color") else {
            return;
        };
        let width = dims_tex.width;
        let height = dims_tex.height;
        if width == 0 || height == 0 {
            return;
        }
        let aspect = width as f32 / height as f32;
        let mut view_proj = cam.view_proj(aspect);
        // RAYTRACING_DESIGN.md §5.2 P4: subpixel camera jitter, applied
        // only when `temporal_upscale` is on (default off = byte-identical
        // to before this param existed). Standard TAA/MetalFX jitter
        // technique: add `jitter * clip.w` to clip.x/clip.y so the offset
        // survives the perspective divide as a CONSTANT NDC shift
        // independent of a vertex's depth. Since every point has
        // homogeneous `w = 1`, `clip.w`'s only nonzero contribution (for
        // this camera's projection matrices — `perspective_rh`/`ortho_rh`
        // in `camera.rs`) comes through the z-column, so it's enough to
        // add `jitter_ndc * view_proj[2][3]` into `view_proj[2][{0,1}]`
        // (column-major storage: `m[col][row]`, matching `mat4_mul_vec4`'s
        // `out[row] = sum_col m[col][row] * v[col]`). `jitter_offset`
        // returns PIXEL units at the render resolution; 1 pixel = `2.0 /
        // dim` in NDC (NDC spans [-1, 1] across `dim` pixels).
        self.jitter_frame_index = self.jitter_frame_index.wrapping_add(1);
        if matches!(ctx.params.get("temporal_upscale"), Some(ParamValue::Bool(true))) {
            let (jx_px, jy_px) =
                crate::metalfx_temporal_upscaler::jitter_offset(self.jitter_frame_index, 8);
            let wz = view_proj[2][3];
            view_proj[2][0] += (jx_px * 2.0 / width as f32) * wz;
            view_proj[2][1] += (jy_px * 2.0 / height as f32) * wz;
        }
        // GBUFFER_DESIGN.md §2 D1: lazy — `velocity` costs nothing unless a
        // consumer actually wired it (checked once per frame, cheap: a
        // step-output lookup, not a texture allocation).
        let velocity_wired = ctx.outputs.texture_2d("velocity").is_some();
        // VOLUMETRIC_LIGHT_DESIGN.md D1/D3 (P2): the sole CPU gate for the
        // whole light-shaft feature, checked once per frame like
        // `velocity_wired`. `depth_wired` decides whether the march reads
        // the graph-allocated resolve target or the internal one (D3:
        // "shafts-on forces the internal Sample0 depth resolve even when
        // `depth` is unwired").
        let wants_shafts_now = wants_shafts(&atmosphere);
        let depth_wired = ctx.outputs.texture_2d("depth").is_some();
        // GBUFFER_DESIGN.md §2 D5 (P2): `None` (no history yet) seeds to
        // THIS frame's own `view_proj`, so a scene's first-ever evaluate()
        // has prev == current and velocity is exactly zero — not
        // approximately. Stored immediately (not gated on `velocity_wired`)
        // so history is tracked continuously: if velocity is wired mid-
        // session, the first wired frame sees the object's REAL prior
        // motion, not a spurious first-frame zero.
        let prev_view_proj = self.prev_view_proj.unwrap_or(view_proj);
        self.prev_view_proj = Some(view_proj);

        // ---- Pass 1 (mutable phase): validate every object's required
        // inputs, compose its model matrix + uniforms, and get-or-compile
        // its pipeline. Structured error + magenta clear + return on the
        // first unmet requirement (no-silent-fallbacks, matching
        // render_mesh / render_copies).
        struct ObjectDraw<'ctx> {
            vertices: &'ctx manifold_gpu::GpuBuffer,
            uniforms: RenderSceneUniforms,
            pipeline: manifold_gpu::GpuRenderPipeline,
            base_color_map: Option<&'ctx manifold_gpu::GpuTexture>,
            /// IMPORT_FIDELITY_DESIGN.md D3/F-P2: the four new optional
            /// per-object texture ports, same "None = unwired, dummy-bind at
            /// draw time" shape as `base_color_map` above.
            normal_map: Option<&'ctx manifold_gpu::GpuTexture>,
            mr_map: Option<&'ctx manifold_gpu::GpuTexture>,
            occlusion_map: Option<&'ctx manifold_gpu::GpuTexture>,
            emissive_map: Option<&'ctx manifold_gpu::GpuTexture>,
            /// GLTF_MATERIAL_EXTENSIONS_DESIGN.md E3/E4/E5 (D1 revised):
            /// same "None = unwired, dummy-bind at draw time" shape.
            sheen_color_map: Option<&'ctx manifold_gpu::GpuTexture>,
            sheen_roughness_map: Option<&'ctx manifold_gpu::GpuTexture>,
            iridescence_map: Option<&'ctx manifold_gpu::GpuTexture>,
            iridescence_thickness_map: Option<&'ctx manifold_gpu::GpuTexture>,
            anisotropy_map: Option<&'ctx manifold_gpu::GpuTexture>,
            /// GLTF_MATERIAL_EXTENSIONS_DESIGN.md E6 (D1 revised — texture-
            /// completion sweep): same "None = unwired" shape.
            clearcoat_map: Option<&'ctx manifold_gpu::GpuTexture>,
            clearcoat_roughness_map: Option<&'ctx manifold_gpu::GpuTexture>,
            clearcoat_normal_map: Option<&'ctx manifold_gpu::GpuTexture>,
            specular_map: Option<&'ctx manifold_gpu::GpuTexture>,
            specular_color_map: Option<&'ctx manifold_gpu::GpuTexture>,
            transmission_map: Option<&'ctx manifold_gpu::GpuTexture>,
            volume_thickness_map: Option<&'ctx manifold_gpu::GpuTexture>,
            /// GLB_XFAIL_BURNDOWN_DESIGN.md D3: this object's per-map-family
            /// sampler settings, order `[base_color, normal, mr, occlusion,
            /// emissive]` — matches `binding_sets`' 22..26 slot order below.
            /// Resolved to actual `&GpuSampler`s in Pass 2 via
            /// `ensure_material_sampler` (ensured for every draw in the
            /// "Ensure cached GPU resources" block, so the Pass-2 cache
            /// lookup can never miss).
            sampler_descs: [MapSamplerDesc; 5],
            /// Wired `instances_n` buffer, or `None` (unwired — bind the
            /// identity stub at draw time; see `identity_instance_stub`).
            instances: Option<&'ctx manifold_gpu::GpuBuffer>,
            /// `buffer_size / 32` when wired, else 1 (identity stub).
            instance_count: u32,
            /// RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md D6: this object's
            /// `mesh_n` input slot's write generation this frame
            /// (`ctx.inputs.slot_generation`) — a component of the shadow
            /// cache key below. `None` only if the (required) mesh port
            /// somehow resolved to an unbound slot — can't happen on the
            /// live path (the `vertices` field above already required a
            /// resolved array), kept `Option` to mirror `slot_generation`'s
            /// signature exactly rather than unwrap a should-never-fail case.
            vertices_generation: Option<u64>,
            /// Same for `instances_n` — `None` both when the port is
            /// genuinely unwired AND (indistinguishably, which is fine: an
            /// unwired port never contributes model-specific staleness) if
            /// somehow unresolved. D6 folds this `Option` into the key
            /// as-is so "unwired" and "wired-then-unwired" both correctly
            /// invalidate any cached key computed under the other state.
            instances_generation: Option<u64>,
            /// IMPORT_FIDELITY_DESIGN.md D8/F-P5: this object's coverage
            /// model — `Blend` routes into the sorted transparent group and
            /// skips every shadow-caster pass; `Opaque`/`Mask` draw in the
            /// existing group, unchanged.
            alpha_mode: AlphaMode,
            /// IMPORT_FIDELITY_DESIGN.md D8/F-P5: view-space depth of this
            /// object's model-matrix translation (the interior's stand-in
            /// for a full local-space bounding-box centroid — no per-object
            /// AABB is tracked anywhere in the graph today, and building
            /// that infra is out of this phase's scope; see the landing
            /// report's confessed-shortcuts field). Larger = farther from
            /// the camera along its forward axis. Used only to order the
            /// Blend group back-to-front; unread for Opaque/Mask objects.
            sort_depth: f32,
            /// GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: this object routes to
            /// Pass B AND wants the opaque-scene-color snapshot bound at
            /// @binding(27) (`Blend` + `transmission_factor > 0`). Every
            /// other draw binds the 1×1 dummy there instead — same always-
            /// bind ABI-stub discipline as `normal_map`/`mr_map`/etc above.
            is_transmissive: bool,
        }

        let instance_size = std::mem::size_of::<InstanceTransform>() as u64;

        let mut draws: Vec<ObjectDraw<'ctx>> = Vec::with_capacity(objects);
        // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: the sole CPU gate for the
        // Pass A/B split below. Only `Blend` objects ever reach Pass B
        // (`is_glass` in `gltf_import.rs` always routes a nonzero
        // `transmission_factor` to `Blend` alpha mode, so this condition and
        // "blend_draw_calls is non-empty" are the same fact) — checking both
        // here keeps that invariant explicit rather than assumed.
        let mut has_transmission = false;

        for n in 0..objects {
            // SCENE_OBJECT_AND_PANEL_V2_DESIGN.md D4 (P2): every object's
            // full bundle (mesh/transform/material/17 maps/instances/
            // visible) arrives on ONE `object_n: Object` port — resolved
            // through `port_index` (built once per frame, above) instead of
            // a per-lookup `NodeInputs::slot` scan, same treatment the
            // legacy per-port lookups got.
            let object_port = &self.object_port_names[n];
            let object_slot_id = port_index.get(object_port.as_ref()).copied();
            let Some(object) = object_slot_id.and_then(|s| ctx.inputs.object_slot(s)) else {
                // Unwired `object_n` (no `node.scene_object` feeding this
                // index yet — an in-progress edit): skip this object
                // entirely, no error. Matches an unwired `visible` object's
                // "no draw, no shadow" treatment below.
                continue;
            };
            if !object.visible {
                // D4: `visible == false` is no draw AND no shadow cast — an
                // invisible object leaves no shadow. Skipping here (never
                // pushed into `draws`) removes it from both the main pass
                // and the shadow-caster pass below, which filters from
                // `draws`.
                continue;
            }
            let mesh_slot = object.mesh;
            let Some(vertices) = mesh_slot.and_then(|s| ctx.inputs.array_slot(s)) else {
                ctx.error(format!(
                    "object_{n}: missing required `vertices` input (its scene_object's `vertices` port is unwired); renderer fell back to magenta clear"
                ));
                if let Some(target) = ctx.outputs.texture_2d("color") {
                    let gpu = ctx.gpu_encoder();
                    gpu.native_enc.clear_texture(target, 1.0, 0.0, 1.0, 1.0);
                }
                return;
            };
            // RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md D6: this object's
            // `mesh_n` write generation, feeds the shadow cache key below.
            let vertices_generation = mesh_slot.and_then(|s| ctx.inputs.slot_generation_of(s));
            let Some(material) = object.material else {
                ctx.error(format!(
                    "object_{n}: missing required `material` input (its scene_object's `material` port is unwired); renderer fell back to magenta clear"
                ));
                if let Some(target) = ctx.outputs.texture_2d("color") {
                    let gpu = ctx.gpu_encoder();
                    gpu.native_enc.clear_texture(target, 1.0, 0.0, 1.0, 1.0);
                }
                return;
            };
            if material.requires_envmap() && envmap_wired.is_none() {
                ctx.error(format!(
                    "{:?} material on `object_{n}` requires `envmap` input but it is unwired; renderer fell back to magenta",
                    material.kind
                ));
                if let Some(target) = ctx.outputs.texture_2d("color") {
                    let gpu = ctx.gpu_encoder();
                    gpu.native_enc.clear_texture(target, 1.0, 0.0, 1.0, 1.0);
                }
                return;
            }
            // `NodeInputs` is `Copy` (bindings.rs) — capture it by value so
            // these lookups don't hold `ctx` borrowed (`ctx.error`/
            // `ctx.outputs`/`ctx.gpu_encoder()` below still need mutably).
            let inputs = ctx.inputs;
            let base_color_map = object.base_color_map.and_then(|s| inputs.texture_2d_slot(s));
            // IMPORT_FIDELITY_DESIGN.md D3/F-P2: the four new optional
            // per-object texture ports.
            let normal_map = object.normal_map.and_then(|s| inputs.texture_2d_slot(s));
            let mr_map = object.mr_map.and_then(|s| inputs.texture_2d_slot(s));
            let occlusion_map = object.occlusion_map.and_then(|s| inputs.texture_2d_slot(s));
            let emissive_map = object.emissive_map.and_then(|s| inputs.texture_2d_slot(s));
            // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E3/E4/E5 (D1 revised).
            let sheen_color_map = object.sheen_color_map.and_then(|s| inputs.texture_2d_slot(s));
            let sheen_roughness_map =
                object.sheen_roughness_map.and_then(|s| inputs.texture_2d_slot(s));
            let iridescence_map = object.iridescence_map.and_then(|s| inputs.texture_2d_slot(s));
            let iridescence_thickness_map =
                object.iridescence_thickness_map.and_then(|s| inputs.texture_2d_slot(s));
            let anisotropy_map = object.anisotropy_map.and_then(|s| inputs.texture_2d_slot(s));
            // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E6 (D1 revised — texture-
            // completion sweep).
            let clearcoat_map = object.clearcoat_map.and_then(|s| inputs.texture_2d_slot(s));
            let clearcoat_roughness_map =
                object.clearcoat_roughness_map.and_then(|s| inputs.texture_2d_slot(s));
            let clearcoat_normal_map =
                object.clearcoat_normal_map.and_then(|s| inputs.texture_2d_slot(s));
            let specular_map = object.specular_map.and_then(|s| inputs.texture_2d_slot(s));
            let specular_color_map =
                object.specular_color_map.and_then(|s| inputs.texture_2d_slot(s));
            let transmission_map = object.transmission_map.and_then(|s| inputs.texture_2d_slot(s));
            let volume_thickness_map =
                object.volume_thickness_map.and_then(|s| inputs.texture_2d_slot(s));

            // `object.transform` already defaults to `Transform::default()`
            // (identity) when scene_object's own `transform` input is
            // unwired (D2) — matches the old scattered params' defaults
            // exactly (pos 0, rot 0, scale 1).
            let t = object.transform;
            let model = model_matrix(t.pos, t.rot_euler, t.scale);
            // GBUFFER_DESIGN.md §2 D5 (P2): `None` at this slot (no history
            // yet — a brand-new node, or the slot right after a rebuild)
            // seeds prev = current, giving THIS object exactly-zero
            // first-frame velocity. Stored immediately after reading (not
            // gated on `velocity_wired`) — see the `prev_view_proj` comment
            // above for why continuous tracking is the correct default.
            let prev_model_n = self.prev_model.get(n).copied().flatten().unwrap_or(model);
            if let Some(slot) = self.prev_model.get_mut(n) {
                *slot = Some(model);
            }
            let mut uniforms = build_uniforms(
                view_proj,
                model,
                &cam,
                &material,
                light_count as f32,
                &atmosphere,
                prev_view_proj,
                prev_model_n,
            );
            if base_color_map.is_some() {
                uniforms.texture_flags[2] = 1.0; // z = base_color_map present (matches resolve_albedo's texture_flags.z gate)
            }
            // IMPORT_FIDELITY_DESIGN.md D3/F-P2 presence flags.
            if normal_map.is_some() {
                uniforms.texture_flags[0] = 1.0; // x = normal_map present (resolve_normal's cotangent-frame gate)
            }
            if mr_map.is_some() {
                uniforms.texture_flags2[0] = 1.0; // x = mr_map present (resolve_mr's gate)
            }
            if occlusion_map.is_some() {
                uniforms.texture_flags2[1] = 1.0; // y = occlusion_map present (resolve_occlusion's gate)
            }
            if emissive_map.is_some() {
                uniforms.texture_flags2[2] = 1.0; // z = emissive_map present (resolve_emissive's gate)
            }
            // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E3/E4/E5 (D1 revised):
            // five new presence flags packed into the five reserved `w`/`y`
            // slots the E1 uniform migration already left inert (no struct
            // growth — same reuse doctrine as ior/specular_factor riding
            // pbr_metallic_roughness.zw and clearcoat riding alpha_params.zw).
            if sheen_color_map.is_some() {
                uniforms.texture_flags[1] = 1.0; // y = sheen_color_map present (resolve_sheen's gate)
            }
            if sheen_roughness_map.is_some() {
                uniforms.texture_flags[3] = 1.0; // w = sheen_roughness_map present
            }
            if iridescence_map.is_some() {
                uniforms.texture_flags2[3] = 1.0; // w = iridescence_map present
            }
            if iridescence_thickness_map.is_some() {
                uniforms.anisotropy_dispersion_params[3] = 1.0; // w = iridescence_thickness_map present
            }
            if anisotropy_map.is_some() {
                uniforms.transmission_volume_params[3] = 1.0; // w = anisotropy_map present
            }
            // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E6 (D1 revised — texture-
            // completion sweep): every reserved single-flag `w` slot the E1
            // migration left is now spent (see the five ifs above), so
            // these seven new presence bits are packed as a bitmask into
            // the LAST two reserved `w` slots (`pbr_specular_tint.w`,
            // `volume_attenuation_color.w`) rather than growing the
            // uniform again — `fs_pbr`'s decode does
            // `u32(round(w)) & (1u << bit)`. Default 0.0 (no bits set) is
            // byte-identical to before this bitmask existed.
            let mut specular_family_flags: u32 = 0;
            if specular_map.is_some() {
                specular_family_flags |= 1; // bit 0 = specular_map present
            }
            if specular_color_map.is_some() {
                specular_family_flags |= 2; // bit 1 = specular_color_map present
            }
            if transmission_map.is_some() {
                specular_family_flags |= 4; // bit 2 = transmission_map present
            }
            if volume_thickness_map.is_some() {
                specular_family_flags |= 8; // bit 3 = volume_thickness_map present
            }
            uniforms.pbr_specular_tint[3] = specular_family_flags as f32;
            let mut clearcoat_family_flags: u32 = 0;
            if clearcoat_map.is_some() {
                clearcoat_family_flags |= 1; // bit 0 = clearcoat_map present
            }
            if clearcoat_roughness_map.is_some() {
                clearcoat_family_flags |= 2; // bit 1 = clearcoat_roughness_map present
            }
            if clearcoat_normal_map.is_some() {
                clearcoat_family_flags |= 4; // bit 2 = clearcoat_normal_map present
            }
            uniforms.volume_attenuation_color[3] = clearcoat_family_flags as f32;

            // GLB_XFAIL_BURNDOWN_DESIGN.md D3: read while `material` is
            // still in scope (it's consumed by `build_uniforms` above by
            // reference, still live here).
            let sampler_descs = [
                material.base_color_sampler,
                material.normal_sampler,
                material.mr_sampler,
                material.occlusion_sampler,
                material.emissive_sampler,
            ];

            let alpha_mode = material.alpha_mode;
            let is_blend = alpha_mode == AlphaMode::Blend;
            let is_transmissive = is_blend && material.transmission_factor > 0.0;
            if is_transmissive {
                has_transmission = true;
            }

            // D11: wired instances_n draws instance_count = buffer_size / 32
            // copies (0 → that object's draw becomes a legal instance-count-0
            // no-op); unwired draws once via the identity stub (bound at
            // Pass 2 — this object carries no self-owned buffer reference).
            let instances_slot = object.instances;
            let instances = instances_slot.and_then(|s| inputs.array_slot(s));
            let instances_generation = instances_slot.and_then(|s| inputs.slot_generation_of(s));
            let instance_count = match instances {
                Some(buf) => (buf.size / instance_size) as u32,
                None => 1,
            };

            let pipeline = {
                let gpu = ctx.gpu_encoder();
                self.pipeline_for(gpu.device, material.kind, velocity_wired, is_blend)
                    .clone()
            };

            // IMPORT_FIDELITY_DESIGN.md D8/F-P5: view-space depth of this
            // object's translation (see the `sort_depth` doc comment above).
            let world_pos = [model[3][0], model[3][1], model[3][2]];
            let sort_depth = (world_pos[0] - cam.pos[0]) * cam.fwd[0]
                + (world_pos[1] - cam.pos[1]) * cam.fwd[1]
                + (world_pos[2] - cam.pos[2]) * cam.fwd[2];

            draws.push(ObjectDraw {
                vertices,
                uniforms,
                pipeline,
                base_color_map,
                normal_map,
                mr_map,
                occlusion_map,
                emissive_map,
                sheen_color_map,
                sheen_roughness_map,
                iridescence_map,
                iridescence_thickness_map,
                anisotropy_map,
                clearcoat_map,
                clearcoat_roughness_map,
                clearcoat_normal_map,
                specular_map,
                specular_color_map,
                transmission_map,
                volume_thickness_map,
                sampler_descs,
                instances,
                instance_count,
                vertices_generation,
                instances_generation,
                alpha_mode,
                sort_depth,
                is_transmissive,
            });
        }

        if draws.is_empty() {
            return;
        }

        // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: peek `color`'s format
        // (idempotent lookup, already called multiple times elsewhere in
        // this fn — see the magenta-clear error paths above) BEFORE the
        // `gpu_encoder()` block below, whose live `&mut GpuEncoder` borrows
        // `ctx` for the whole block and would conflict with a `ctx.outputs`
        // access from inside it.
        let opaque_scene_color_target_format =
            has_transmission.then(|| ctx.outputs.texture_2d("color").map(|t| t.format)).flatten();

        // ---- Ensure cached GPU resources (mutable phase). ----
        let has_casters = !casters.is_empty();
        {
            let gpu = ctx.gpu_encoder();
            if self.depth_stencil.is_none() {
                self.depth_stencil = Some(gpu.device.create_depth_stencil_state(
                    &manifold_gpu::GpuDepthStencilDesc {
                        compare: manifold_gpu::GpuCompareFunction::Less,
                        write_enabled: true,
                    },
                ));
            }
            // IMPORT_FIDELITY_DESIGN.md D8/F-P5: same compare, write disabled
            // — the sorted transparent group's depth-stencil state.
            if self.blend_depth_stencil.is_none() {
                self.blend_depth_stencil = Some(gpu.device.create_depth_stencil_state(
                    &manifold_gpu::GpuDepthStencilDesc {
                        compare: manifold_gpu::GpuCompareFunction::Less,
                        write_enabled: false,
                    },
                ));
            }
            self.ensure_msaa_targets(gpu.device, width, height);
            // GBUFFER_DESIGN.md §2 D1/D5 (P2): the velocity aux-MRT
            // memoryless target is allocated ONLY when wired this frame —
            // this call site (not `ensure_msaa_targets`, which always runs)
            // is the actual zero-cost-when-unwired enforcement point.
            if velocity_wired {
                self.ensure_velocity_msaa_target(gpu.device, width, height);
            }
            self.ensure_sampler(gpu.device);
            // GLB_XFAIL_BURNDOWN_DESIGN.md D3: ensure every distinct
            // per-map-family sampler this frame's draws need. Runs before
            // Pass 2 builds `binding_sets`, so every lookup there is
            // guaranteed a cache hit.
            for draw in &draws {
                for desc in draw.sampler_descs {
                    self.ensure_material_sampler(gpu.device, desc);
                }
            }
            self.ensure_dummy_texture(gpu.device);
            // IMPORT_FIDELITY_DESIGN.md D2/F-P1: split-sum IBL resources —
            // always ensured (fixed size, allocated once) so
            // `@binding(16..18)` always has something valid, regardless of
            // whether `envmap` is wired this frame.
            self.ensure_ibl_resources(gpu.device);
            // Identity instance stub (D11) — bound to any object's
            // instances_n when unwired, both in the main pass and every
            // caster's shadow pass below.
            self.ensure_identity_instance_stub(gpu.device);
            // Shadow ABI stubs (comparison sampler + 1×1 dummy depth) are
            // always needed — the main shader declares @binding(10..14) even
            // in a scene with no casters. The shadow *pipeline* + per-caster
            // maps are created only when a caster exists (unwired = zero cost).
            self.ensure_shadow_binding_stubs(gpu.device);
            if has_casters {
                self.ensure_shadow_pass(gpu.device);
                for (slot, l) in casters.iter().enumerate() {
                    self.ensure_shadow_map(gpu.device, slot, l.shadow_resolution);
                }
            } else if has_transmission {
                // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: the transmissive
                // opaque-depth prepass below reuses `shadow_pipeline` (a
                // depth-only pipeline fed the camera's `view_proj` instead
                // of a light's) even when there are zero shadow casters.
                self.ensure_shadow_pass(gpu.device);
            }
            // E2a: allocate the Depth32Float snapshot Pass B depth-tests
            // against, plus the opaque-scene-color snapshot itself. Both
            // must happen HERE (this block's `{ let gpu = ... }` scope,
            // before `identity_stub` and friends take long-lived immutable
            // borrows of `self` below) — the same `&mut self` ensure calls
            // deferred to right before Pass 2 fetches `target` (the natural
            // place otherwise) would conflict with those borrows under NLL.
            if has_transmission {
                self.ensure_opaque_depth_snapshot(gpu.device, width, height);
                if let Some(format) = opaque_scene_color_target_format {
                    self.ensure_opaque_scene_color(gpu.device, width, height, format);
                }
            }
            // VOLUMETRIC_LIGHT_DESIGN.md D1/D3 (P2): the whole feature's
            // real GPU cost gate. `wants_shafts_now == false` (the default)
            // means none of these run and none of these textures/pipelines
            // are ever allocated — the "unwired = zero cost" contract
            // extended from fog to shafts (V1).
            if wants_shafts_now {
                self.ensure_shaft_pipelines(gpu.device);
                let half_w = width.div_ceil(2).max(1);
                let half_h = height.div_ceil(2).max(1);
                self.ensure_shaft_half_res(gpu.device, half_w, half_h);
                if !depth_wired {
                    self.ensure_shaft_depth_internal(gpu.device, width, height);
                }
            }
            // Rotate + (re)size the light ring buffer, then write this
            // frame's light data into the current ring slot. Rotating across
            // FRAMES_IN_FLIGHT buffers guarantees the CPU never overwrites a
            // buffer an in-flight frame is still reading (kills the 4KB
            // setBytes cap that bounded the old Bytes binding to 127 lights).
            let needed = (light_data.len() * std::mem::size_of::<[f32; 4]>()) as u64;
            if self.light_buffers.len() < FRAMES_IN_FLIGHT || self.light_capacity < needed {
                let cap = needed.max(self.light_capacity).max(64).next_power_of_two();
                self.light_buffers = (0..FRAMES_IN_FLIGHT)
                    .map(|_| gpu.device.create_buffer_shared(cap))
                    .collect();
                self.light_capacity = cap;
            }
            self.light_frame = (self.light_frame + 1) % FRAMES_IN_FLIGHT;
            unsafe {
                self.light_buffers[self.light_frame]
                    .write(0, bytemuck::cast_slice(&light_data));
            }
        }

        // ---- Split-sum IBL convolution (IMPORT_FIDELITY_DESIGN.md
        // D2/F-P1). Runs before the main pass so the prefiltered/irradiance/
        // LUT textures are ready to sample; see `run_ibl_convolution`'s doc
        // comment for the cache-vs-correctness tradeoff on the two
        // envmap-dependent resources. ----
        {
            // Read before `ctx.gpu_encoder()` takes a mutable borrow of ctx.
            let envmap_generation = ctx.inputs.slot_generation("envmap");
            let rebuild_epoch = ctx.rebuild_epoch;
            let gpu = ctx.gpu_encoder();
            let sampler = self.sampler.as_ref().expect("ensured").clone();
            self.run_ibl_convolution(gpu, &sampler, envmap_wired, envmap_generation, rebuild_epoch);
        }

        // ---- Shadow depth pre-passes. One depth-only pass per caster
        // (cleared once), every object drawn through that light's
        // view-projection into its private Depth32Float map. Runs before the
        // main lit pass so the maps are ready to sample; skipped entirely
        // when no light casts (has_casters == false → zero passes). ----
        let vsize = std::mem::size_of::<MeshVertex>() as u64;
        let vcount = |buf: &manifold_gpu::GpuBuffer| ((buf.size / vsize) as u32 / 3) * 3;
        // D11: the shadow pass instances too — bound once here, reused by
        // Pass 2 below (both only ever take an immutable borrow of self).
        let identity_stub = self.identity_instance_stub.as_ref().expect("ensured");
        // IMPORT_FIDELITY_DESIGN.md D8/F-P5: "a window must not throw an
        // opaque shadow" — Blend objects are excluded from every caster's
        // depth-only pass below, never just the main draw.
        let shadow_caster_draws: Vec<&ObjectDraw> = draws
            .iter()
            .filter(|d| d.alpha_mode != AlphaMode::Blend)
            .collect();
        if has_casters {
            let shadow_pipeline = self.shadow_pipeline.as_ref().expect("ensured").clone();
            let shadow_ds = self.shadow_depth_stencil.as_ref().expect("ensured");
            for (slot, l) in casters.iter().enumerate() {
                let Some((_, shadow_map)) = self.shadow_maps[slot].as_ref() else {
                    continue;
                };
                let vp = l.shadow_view_proj();

                // RENDER_SCENE_PERF_OPTIMIZATION_DESIGN.md D6: this caster's
                // dirty-check key — everything the depth-only batch below
                // reads. `shadow_view_proj()` is a pure function of the
                // light alone (light.rs), so a static light reproduces the
                // exact same `vp` bytes every frame; the per-draw component
                // list catches every other input (geometry, transforms,
                // instancing). Hashed into a fixed hasher — zero per-frame
                // allocation (CLAUDE.md hot-path discipline); `AHasher` is
                // already this crate's fast-hash workhorse (`ahash::AHashMap`
                // throughout `execution.rs`).
                use std::hash::{Hash, Hasher};
                let mut hasher = ahash::AHasher::default();
                hasher.write(bytemuck::bytes_of(&vp));
                hasher.write_u32(l.shadow_resolution);
                hasher.write_usize(shadow_caster_draws.len());
                for d in &shadow_caster_draws {
                    hasher.write(bytemuck::bytes_of(&d.uniforms.model));
                    d.vertices_generation.hash(&mut hasher);
                    d.instances_generation.hash(&mut hasher);
                    hasher.write_u32(vcount(d.vertices));
                    hasher.write_u32(d.instance_count);
                }
                // D6: the rebuild-epoch term — guards against a topology
                // rebuild carrying this primitive's own Rust state (this
                // struct, including `shadow_cache_keys`) into a BRAND NEW
                // executor whose slot generations reset to 0 (see
                // `Executor::rebuild_epoch`'s doc comment for the full
                // hazard). Folding it in means a key computed under a prior
                // executor lifetime can never coincidentally match this one.
                hasher.write_u64(ctx.rebuild_epoch);
                let shadow_key = hasher.finish();

                // I1: never serve on ANY mismatch — including the `None` a
                // fresh primitive (or a resolution/topology change that
                // reset `shadow_cache_keys`) starts with. A full match means
                // `shadow_maps[slot]`'s PERSISTED texture (never cleared
                // except on resolution change — see `ensure_shadow_map`)
                // already holds exactly this content, so the depth-only
                // batch this caster would otherwise issue is redundant.
                if self.shadow_cache_keys[slot] == Some(shadow_key) {
                    continue;
                }
                self.shadow_cache_keys[slot] = Some(shadow_key);

                let shadow_uniforms: Vec<ShadowUniforms> = shadow_caster_draws
                    .iter()
                    .map(|d| ShadowUniforms {
                        light_view_proj: vp,
                        model: d.uniforms.model,
                    })
                    .collect();
                let shadow_bindings: Vec<[GpuBinding; 3]> = shadow_caster_draws
                    .iter()
                    .zip(&shadow_uniforms)
                    .map(|(d, su)| {
                        [
                            GpuBinding::Bytes {
                                binding: 0,
                                data: bytemuck::bytes_of(su),
                            },
                            GpuBinding::Buffer {
                                binding: 1,
                                buffer: d.vertices,
                                offset: 0,
                            },
                            GpuBinding::Buffer {
                                binding: 2,
                                buffer: d.instances.unwrap_or(identity_stub),
                                offset: 0,
                            },
                        ]
                    })
                    .collect();
                let shadow_draws: Vec<manifold_gpu::DepthMsaaDraw> = shadow_caster_draws
                    .iter()
                    .zip(&shadow_bindings)
                    .map(|(d, b)| {
                        manifold_gpu::GpuEncoder::depth_msaa_draw(
                            &shadow_pipeline,
                            b,
                            vcount(d.vertices),
                            d.instance_count,
                        )
                    })
                    .collect();
                ctx.gpu_encoder()
                    .native_enc
                    .draw_instanced_depth_only_batch(
                        shadow_map,
                        shadow_ds,
                        &shadow_draws,
                        "node.render_scene shadow",
                    );
            }
        }

        // ---- GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: opaque-only camera-
        // space depth prepass into `opaque_depth_snapshot`, so Pass B (the
        // transmissive/blend group, drawn after Pass A below resolves) can
        // depth-test against Pass A's result as a real Metal depth
        // ATTACHMENT. Reuses `shadow_pipeline`/`shadow_depth_stencil` (a
        // depth-only pipeline + write-enabled-Less state), fed the CAMERA's
        // `view_proj` instead of a light's — same draw set as Pass A's
        // opaque/mask group (`shadow_caster_draws` already excludes Blend).
        // Skipped entirely when the scene has no transmissive object
        // (zero-transmission = zero extra passes, same lazy contract as the
        // shaft/velocity features above). ----
        if has_transmission {
            let opaque_depth_pipeline = self.shadow_pipeline.as_ref().expect("ensured above").clone();
            let opaque_depth_ds = self.shadow_depth_stencil.as_ref().expect("ensured above");
            let opaque_depth_snapshot = self.opaque_depth_snapshot.as_ref().expect("ensured above");
            let cam_uniforms: Vec<ShadowUniforms> = shadow_caster_draws
                .iter()
                .map(|d| ShadowUniforms {
                    light_view_proj: view_proj,
                    model: d.uniforms.model,
                })
                .collect();
            let cam_bindings: Vec<[GpuBinding; 3]> = shadow_caster_draws
                .iter()
                .zip(&cam_uniforms)
                .map(|(d, su)| {
                    [
                        GpuBinding::Bytes {
                            binding: 0,
                            data: bytemuck::bytes_of(su),
                        },
                        GpuBinding::Buffer {
                            binding: 1,
                            buffer: d.vertices,
                            offset: 0,
                        },
                        GpuBinding::Buffer {
                            binding: 2,
                            buffer: d.instances.unwrap_or(identity_stub),
                            offset: 0,
                        },
                    ]
                })
                .collect();
            let cam_draws: Vec<manifold_gpu::DepthMsaaDraw> = shadow_caster_draws
                .iter()
                .zip(&cam_bindings)
                .map(|(d, b)| {
                    manifold_gpu::GpuEncoder::depth_msaa_draw(
                        &opaque_depth_pipeline,
                        b,
                        vcount(d.vertices),
                        d.instance_count,
                    )
                })
                .collect();
            ctx.gpu_encoder()
                .native_enc
                .draw_instanced_depth_only_batch(
                    opaque_depth_snapshot,
                    opaque_depth_ds,
                    &cam_draws,
                    "node.render_scene E2a opaque depth snapshot",
                );
        }

        // ---- Pass 2 (immutable phase): draw. Every object composites into
        // ONE 4x-MSAA color+depth pass (cleared once); the shared depth
        // buffer resolves inter-object occlusion, and the pass resolves out
        // to the single-sample `target` at the end.
        let Some(target) = ctx.outputs.texture_2d("color") else {
            return;
        };
        // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: `opaque_scene_color` was
        // already (re)allocated above, sized to this exact `target`'s
        // format — see `opaque_scene_color_target_format`'s doc comment for
        // why that ensure call has to happen before this point.
        // GBUFFER_DESIGN.md §2 D1: `None` when unwired — the graph compiler
        // never assigns "depth" a step-output binding in that case (same
        // lazy mechanism as `render_mesh`'s G-buffer outputs), so this pass
        // costs zero new bytes unless a consumer actually wired it (I1).
        let graph_depth_resolve_target = ctx.outputs.texture_2d("depth");
        // VOLUMETRIC_LIGHT_DESIGN.md D3 (P2): when shafts are on and `depth`
        // is unwired, resolve into the internal target instead (ensured
        // above) so the march has a depth source regardless — "shafts-on
        // forces the internal Sample0 depth resolve even when `depth` is
        // unwired". When `depth` IS wired, the graph's own resolve target
        // is used for BOTH the graph consumer and the march (one resolve,
        // two readers).
        let depth_resolve_target = graph_depth_resolve_target
            .or(if wants_shafts_now { self.shaft_depth_internal.as_ref() } else { None });
        // GBUFFER_DESIGN.md §2 D1/D5 (P2): same lazy rule as `depth` —
        // `None` when unwired, costing zero new bytes (I1).
        let velocity_resolve_target = ctx.outputs.texture_2d("velocity");
        let depth_stencil = self.depth_stencil.as_ref().expect("just inserted");
        let depth_tex = self.depth_texture.as_ref().expect("just inserted");
        let msaa_color = self.msaa_color.as_ref().expect("just inserted");
        let sampler = self.sampler.as_ref().expect("just inserted");
        // GLB_XFAIL_BURNDOWN_DESIGN.md D3: per-draw, per-map-family sampler
        // lookup — every descriptor was ensured into the cache above, so
        // this is a guaranteed hit, never a fallback/dummy.
        let material_samplers = &self.material_samplers;
        let sampler_for = |desc: MapSamplerDesc| -> &manifold_gpu::GpuSampler {
            material_samplers
                .get(&Self::sampler_cache_key(desc))
                .expect("ensured in the 'Ensure cached GPU resources' block above")
        };
        let dummy = self.dummy_texture.as_ref().expect("just inserted");
        let shadow_sampler = self.shadow_sampler.as_ref().expect("stubs ensured");
        let dummy_depth = self.dummy_depth.as_ref().expect("stubs ensured");
        let envmap_texture = envmap_wired.unwrap_or(dummy);
        // Shadow map per slot → the real map if that slot has a caster, else
        // the 1×1 dummy depth. The shader never samples a −1 (non-caster)
        // slot, but every declared @binding(10..13) must be a valid depth
        // texture. Hand-unrolled for K=4 (WGSL has no dynamic texture-binding
        // indexing); the assert trips if K changes and this list doesn't.
        const _: () = assert!(
            MAX_SHADOW_CASTING_LIGHTS == 4,
            "shadow-map bindings @10..13 + shader switch are hand-unrolled for K=4"
        );
        let shadow_tex = |slot: usize| -> &manifold_gpu::GpuTexture {
            self.shadow_maps[slot]
                .as_ref()
                .map(|(_, t)| t)
                .unwrap_or(dummy_depth)
        };
        let shadow_0 = shadow_tex(0);
        let shadow_1 = shadow_tex(1);
        let shadow_2 = shadow_tex(2);
        let shadow_3 = shadow_tex(3);

        let vertex_size = std::mem::size_of::<MeshVertex>() as u64;
        let vertex_count = |draw: &ObjectDraw| ((draw.vertices.size / vertex_size) as u32 / 3) * 3;

        if !draws.iter().any(|d| vertex_count(d) > 0) {
            // Every object had zero drawable vertices — clear so stale
            // pool contents don't leak through (matches render_mesh's
            // vertex_count == 0 fallback).
            ctx.gpu_encoder().native_enc.clear_texture(target, 0.0, 0.0, 0.0, 0.0);
            return;
        }

        // Binding arrays must outlive the batch call, so build them all
        // first, then reference each from a `DepthMsaaDraw`. The light buffer
        // (this frame's ring slot) and caster table are scene-wide — every
        // object's set borrows the same ones.
        let light_buffer = &self.light_buffers[self.light_frame];
        let caster_bytes: &[u8] = bytemuck::cast_slice(&caster_table);
        let prefiltered_specular = self.prefiltered_specular.as_ref().expect("ensured");
        let irradiance_map = self.irradiance_map.as_ref().expect("ensured");
        let brdf_lut = self.brdf_lut.as_ref().expect("ensured");
        // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: `None` whenever
        // `has_transmission` is false — nothing below reads it in that case
        // (`draw.is_transmissive` can only be true when `has_transmission`
        // is), but the option lets the same closure serve both cases
        // without a branch on `has_transmission` itself.
        let opaque_scene_color_snapshot = self.opaque_scene_color.as_ref();
        let binding_sets: Vec<[GpuBinding; 41]> = draws
            .iter()
            .map(|draw| {
                [
                    GpuBinding::Bytes {
                        binding: 0,
                        data: bytemuck::bytes_of(&draw.uniforms),
                    },
                    GpuBinding::Buffer {
                        binding: 1,
                        buffer: draw.vertices,
                        offset: 0,
                    },
                    GpuBinding::Texture {
                        binding: 2,
                        texture: envmap_texture,
                    },
                    GpuBinding::Sampler {
                        binding: 3,
                        sampler,
                    },
                    // IMPORT_FIDELITY_DESIGN.md D3/F-P2: normal_map_n (D4
                    // cotangent-frame tangent-space reconstruction).
                    GpuBinding::Texture {
                        binding: 4,
                        texture: draw.normal_map.unwrap_or(dummy),
                    },
                    // binding(5): roughness_map — permanently dead stub, see
                    // shader-side comment; always the dummy.
                    GpuBinding::Texture {
                        binding: 5,
                        texture: dummy,
                    },
                    GpuBinding::Texture {
                        binding: 6,
                        texture: draw.base_color_map.unwrap_or(dummy),
                    },
                    // binding(7): metallic_map — permanently dead stub, see
                    // shader-side comment; always the dummy.
                    GpuBinding::Texture {
                        binding: 7,
                        texture: dummy,
                    },
                    // Lights: ring-buffered storage buffer (was a 4KB-capped
                    // Bytes bind). Holds one zeroed entry when no light is
                    // wired; the shader gates reads on `light_count` (D4).
                    GpuBinding::Buffer {
                        binding: 8,
                        buffer: light_buffer,
                        offset: 0,
                    },
                    // Caster table (fixed K×5 vec4, zeroed for empty slots) —
                    // always bound, same D4 discipline as the light buffer.
                    GpuBinding::Bytes {
                        binding: 9,
                        data: caster_bytes,
                    },
                    GpuBinding::Texture {
                        binding: 10,
                        texture: shadow_0,
                    },
                    GpuBinding::Texture {
                        binding: 11,
                        texture: shadow_1,
                    },
                    GpuBinding::Texture {
                        binding: 12,
                        texture: shadow_2,
                    },
                    GpuBinding::Texture {
                        binding: 13,
                        texture: shadow_3,
                    },
                    GpuBinding::Sampler {
                        binding: 14,
                        sampler: shadow_sampler,
                    },
                    // D11: per-object instances_n, or the identity stub when
                    // that object leaves it unwired.
                    GpuBinding::Buffer {
                        binding: 15,
                        buffer: draw.instances.unwrap_or(identity_stub),
                        offset: 0,
                    },
                    // IMPORT_FIDELITY_DESIGN.md D2/F-P1: split-sum IBL.
                    // Always bound (same always-bind ABI-stub discipline as
                    // bindings 4/5/7/10-14 above) — `ensure_ibl_resources`
                    // guarantees these three exist regardless of whether
                    // `envmap` is wired this frame; `fs_pbr` only actually
                    // samples them for PBR materials, which already require
                    // `envmap` wired (the `requires_envmap` gate above).
                    GpuBinding::Texture {
                        binding: 16,
                        texture: prefiltered_specular,
                    },
                    GpuBinding::Texture {
                        binding: 17,
                        texture: irradiance_map,
                    },
                    GpuBinding::Texture {
                        binding: 18,
                        texture: brdf_lut,
                    },
                    // IMPORT_FIDELITY_DESIGN.md D3/F-P2: the three NEW
                    // per-object maps (normal_map_n reuses binding(4) above).
                    // Same always-bind ABI-stub discipline.
                    GpuBinding::Texture {
                        binding: 19,
                        texture: draw.mr_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 20,
                        texture: draw.occlusion_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 21,
                        texture: draw.emissive_map.unwrap_or(dummy),
                    },
                    // GLB_XFAIL_BURNDOWN_DESIGN.md D3: per-map-family
                    // samplers, one per texture family — no longer one
                    // scene-wide REPEAT sampler. Order matches
                    // `ObjectDraw::sampler_descs` / `Material`'s field order.
                    GpuBinding::Sampler {
                        binding: 22,
                        sampler: sampler_for(draw.sampler_descs[0]), // base_color
                    },
                    GpuBinding::Sampler {
                        binding: 23,
                        sampler: sampler_for(draw.sampler_descs[1]), // normal
                    },
                    GpuBinding::Sampler {
                        binding: 24,
                        sampler: sampler_for(draw.sampler_descs[2]), // mr
                    },
                    GpuBinding::Sampler {
                        binding: 25,
                        sampler: sampler_for(draw.sampler_descs[3]), // occlusion
                    },
                    GpuBinding::Sampler {
                        binding: 26,
                        sampler: sampler_for(draw.sampler_descs[4]), // emissive
                    },
                    // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: opaque-scene-
                    // color snapshot — bound for real only on the object
                    // that will actually sample it (E2b), the 1×1 dummy for
                    // everything else. Declared in the WGSL (pipeline-layout
                    // correctness) but not yet read by `fs_pbr` this phase —
                    // no shading change.
                    GpuBinding::Texture {
                        binding: 27,
                        texture: if draw.is_transmissive {
                            opaque_scene_color_snapshot
                                .expect("ensured above whenever any draw.is_transmissive is true")
                        } else {
                            dummy
                        },
                    },
                    GpuBinding::Sampler {
                        binding: 28,
                        sampler,
                    },
                    // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E3/E4/E5 (D1
                    // revised): sheen/iridescence/anisotropy extension
                    // textures. Same always-bind ABI-stub discipline as
                    // 19-21; sampled with the existing base_color_sampler
                    // (binding 22, sRGB colour maps) / mr_sampler (binding
                    // 24, linear data maps) rather than adding five more
                    // dedicated sampler bindings — a documented v1
                    // simplification (no per-extension-map sampler wrap/
                    // filter override; every extension texture gets that
                    // family's default repeat/linear behavior).
                    GpuBinding::Texture {
                        binding: 29,
                        texture: draw.sheen_color_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 30,
                        texture: draw.sheen_roughness_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 31,
                        texture: draw.iridescence_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 32,
                        texture: draw.iridescence_thickness_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 33,
                        texture: draw.anisotropy_map.unwrap_or(dummy),
                    },
                    // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E6 (D1 revised —
                    // texture-completion sweep): clearcoat/specular/
                    // transmission/volume-thickness extension textures,
                    // same always-bind ABI-stub discipline + shared-sampler
                    // simplification as 29-33 above.
                    GpuBinding::Texture {
                        binding: 34,
                        texture: draw.clearcoat_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 35,
                        texture: draw.clearcoat_roughness_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 36,
                        texture: draw.clearcoat_normal_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 37,
                        texture: draw.specular_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 38,
                        texture: draw.specular_color_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 39,
                        texture: draw.transmission_map.unwrap_or(dummy),
                    },
                    GpuBinding::Texture {
                        binding: 40,
                        texture: draw.volume_thickness_map.unwrap_or(dummy),
                    },
                ]
            })
            .collect();
        // IMPORT_FIDELITY_DESIGN.md D8/F-P5: split into the existing
        // opaque/mask group (order unchanged — a zero-Blend scene produces
        // byte-identical `draw_calls` to before this phase) and the sorted
        // transparent group, drawn as `second_pass` in the SAME encoder pass
        // right after (occlusion by opaque geometry falls out of the shared,
        // still-live MSAA depth buffer; no separate resolve/reclear).
        let mut draw_calls: Vec<manifold_gpu::DepthMsaaDraw> = Vec::with_capacity(draws.len());
        let mut blend_entries: Vec<(f32, manifold_gpu::DepthMsaaDraw)> = Vec::new();
        for (draw, bindings) in draws.iter().zip(&binding_sets) {
            let call = manifold_gpu::GpuEncoder::depth_msaa_draw(
                &draw.pipeline,
                bindings,
                vertex_count(draw),
                draw.instance_count,
            );
            if draw.alpha_mode == AlphaMode::Blend {
                blend_entries.push((draw.sort_depth, call));
            } else {
                draw_calls.push(call);
            }
        }
        // Back-to-front: farthest object (largest view-space depth along
        // the camera's forward axis) drawn first, so nearer glass blends
        // correctly over farther glass.
        blend_entries.sort_by(|a, b| b.0.partial_cmp(&a.0).unwrap_or(std::cmp::Ordering::Equal));
        let blend_draw_calls: Vec<manifold_gpu::DepthMsaaDraw> =
            blend_entries.into_iter().map(|(_, call)| call).collect();
        // GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: when the scene has a
        // transmissive object, the Blend group is pulled OUT of Pass A
        // entirely and drawn as a separate Pass B below (after the opaque-
        // color snapshot blit) instead of as Pass A's in-pass `second_pass`
        // group — memoryless `msaa_color`/`msaa_depth` cannot survive past
        // Pass A's end, so a transmissive fragment can only sample "the
        // scene behind it" from a real resolved snapshot taken between the
        // two passes. A zero-transmission scene (`has_transmission ==
        // false`, the overwhelming common case) takes the exact `second_pass
        // = Some(...)` path unchanged from before this phase — byte-
        // identical single pass, same as today.
        let second_pass = if has_transmission || blend_draw_calls.is_empty() {
            None
        } else {
            Some((
                self.blend_depth_stencil.as_ref().expect("ensured"),
                blend_draw_calls.as_slice(),
            ))
        };

        // GBUFFER_DESIGN.md §2 D5 (P2): the aux-MRT slot P1 built but never
        // exercised. `velocity_pair` is `Some` only when BOTH this node's
        // own memoryless velocity_msaa scratch AND the graph-allocated
        // single-sample resolve target exist — i.e. exactly when
        // `velocity_wired` gated `ensure_velocity_msaa_target` above.
        // `aux_color_storage`/`aux_color` follow the same "declare outside,
        // conditionally initialize, borrow" shape needed to hand the pass a
        // `&[(&GpuTexture, &GpuTexture)]` from either branch without an
        // allocation.
        let velocity_pair = match (self.velocity_msaa.as_ref(), velocity_resolve_target) {
            (Some(msaa), Some(resolve)) => Some((msaa, resolve)),
            _ => None,
        };
        let aux_color_storage: [(&manifold_gpu::GpuTexture, &manifold_gpu::GpuTexture); 1];
        let aux_color: &[(&manifold_gpu::GpuTexture, &manifold_gpu::GpuTexture)] =
            if let Some(pair) = velocity_pair {
                aux_color_storage = [pair];
                &aux_color_storage
            } else {
                &[]
            };

        let pass_desc = manifold_gpu::DepthMsaaPassDesc {
            msaa_color,
            resolve_target: target,
            msaa_depth: depth_tex,
            depth_resolve: depth_resolve_target,
            aux_color,
            depth_stencil_state: depth_stencil,
            second_pass,
        };
        ctx.gpu_encoder()
            .native_enc
            .draw_instanced_depth_msaa_batch_desc(&pass_desc, &draw_calls, "node.render_scene");

        // ---- GLTF_MATERIAL_EXTENSIONS_DESIGN.md E2a: the snapshot + Pass B
        // seam. Pass A above just resolved the fully-shaded opaque scene
        // into `target`; blit it into `opaque_scene_color` (the texture an
        // E2b transmissive shader will sample), then draw the Blend group
        // as its own single-sample pass, loading (not clearing) both
        // `target`'s color and `opaque_depth_snapshot`'s depth so it
        // composites onto Pass A's result and depth-tests against it. No
        // MSAA on this pass (`docs/GLTF_MATERIAL_EXTENSIONS_DESIGN.md` E2a
        // brief D3/E2a note: memoryless MSAA color can't be re-loaded across
        // a pass boundary, and a non-memoryless MSAA target would cost real
        // VRAM gated only on this — see the confessed-shortcuts field in
        // this phase's landing report for why single-sample was chosen).
        // Entirely skipped when `has_transmission` is false — zero bytes,
        // zero passes, zero behavior change for every scene without glass. ----
        if has_transmission {
            let opaque_scene_color = self.opaque_scene_color.as_ref().expect("ensured above");
            let opaque_depth_snapshot = self.opaque_depth_snapshot.as_ref().expect("ensured above");
            let blend_depth_stencil = self.blend_depth_stencil.as_ref().expect("ensured");
            let gpu = ctx.gpu_encoder();
            gpu.native_enc
                .copy_texture_to_texture(target, opaque_scene_color, width, height, 1);
            // E2b: level 0 is fresh from the blit above; levels 1.. are
            // stale until regenerated (same "regen on every write" rule
            // `node.gltf_texture_source` step 8 follows) — `fs_pbr`'s
            // roughness-driven refraction blur samples this chain, so it
            // must be current EVERY frame the snapshot is retaken (unlike a
            // static imported texture, this content changes every frame the
            // camera or scene moves).
            if opaque_scene_color.mip_level_count() > 1 {
                gpu.native_enc.generate_mipmaps(opaque_scene_color);
            }
            if !blend_draw_calls.is_empty() {
                gpu.native_enc.draw_instanced_depth_batch(
                    target,
                    opaque_depth_snapshot,
                    blend_depth_stencil,
                    &blend_draw_calls,
                    manifold_gpu::GpuLoadAction::Load,
                    manifold_gpu::GpuLoadAction::Load,
                    "node.render_scene E2a transmissive pass B",
                );
            }
        }

        // ---- VOLUMETRIC_LIGHT_DESIGN.md D2/D3 (P2): light-shaft march +
        // depth-aware bilateral upsample + additive composite. Runs ONLY
        // when `wants_shafts_now` (the V1/D1 gate) — the default
        // `shaft_intensity == 0` never reaches this block, so the rest of
        // this function's behavior (and every byte it produces) is
        // untouched when shafts are off. ----
        if wants_shafts_now {
            let half_w = self.shaft_half_width;
            let half_h = self.shaft_half_height;
            let full_depth = depth_resolve_target.expect("ensured above: wants_shafts_now => Some");
            let half_depth = self.shaft_depth_half.as_ref().expect("ensured above");
            let inscatter = self.shaft_inscatter.as_ref().expect("ensured above");
            let downsample_pipeline = self.shaft_downsample_pipeline.as_ref().expect("ensured above");
            let march_pipeline = self.shaft_march_pipeline.as_ref().expect("ensured above");
            let composite_pipeline = self.shaft_composite_pipeline.as_ref().expect("ensured above");

            {
                let gpu = ctx.gpu_encoder();
                gpu.native_enc.dispatch_compute(
                    downsample_pipeline,
                    &[
                        GpuBinding::Texture { binding: 0, texture: full_depth },
                        GpuBinding::Texture { binding: 1, texture: half_depth },
                    ],
                    [half_w.div_ceil(16), half_h.div_ceil(16), 1],
                    "node.render_scene shaft downsample",
                );
            }

            let fov_y = match cam.mode {
                crate::node_graph::camera::CameraMode::Perspective { fov_y } => fov_y,
                crate::node_graph::camera::CameraMode::Orthographic { .. } => {
                    std::f32::consts::FRAC_PI_3
                }
            };
            let steps = shaft_step_count(atmosphere.shaft_quality) as f32;
            let march_uniforms = ShaftMarchUniforms {
                camera_pos: [cam.pos[0], cam.pos[1], cam.pos[2], cam.near],
                camera_right: [cam.right[0], cam.right[1], cam.right[2], cam.far],
                camera_up: [cam.up[0], cam.up[1], cam.up[2], fov_y],
                camera_fwd: [cam.fwd[0], cam.fwd[1], cam.fwd[2], aspect],
                fog_shaft: [
                    atmosphere.fog_density,
                    atmosphere.height_falloff,
                    atmosphere.shaft_anisotropy,
                    atmosphere.shaft_intensity,
                ],
                misc: [steps, shaft_light_count as f32, cam.lens.exposure_ev, 0.0],
            };
            let shaft_light_bytes: &[u8] = bytemuck::cast_slice(&shaft_light_data);
            {
                let gpu = ctx.gpu_encoder();
                gpu.native_enc.dispatch_compute(
                    march_pipeline,
                    &[
                        GpuBinding::Bytes { binding: 0, data: bytemuck::bytes_of(&march_uniforms) },
                        GpuBinding::Texture { binding: 1, texture: half_depth },
                        GpuBinding::Bytes { binding: 2, data: shaft_light_bytes },
                        GpuBinding::Bytes { binding: 3, data: caster_bytes },
                        GpuBinding::Texture { binding: 4, texture: shadow_0 },
                        GpuBinding::Texture { binding: 5, texture: shadow_1 },
                        GpuBinding::Texture { binding: 6, texture: shadow_2 },
                        GpuBinding::Texture { binding: 7, texture: shadow_3 },
                        GpuBinding::Sampler { binding: 8, sampler: shadow_sampler },
                        GpuBinding::Texture { binding: 9, texture: inscatter },
                    ],
                    [half_w.div_ceil(16), half_h.div_ceil(16), 1],
                    "node.render_scene shaft march",
                );
            }

            let composite_uniforms = ShaftCompositeUniforms {
                near_far: [cam.near, cam.far, 0.0, 0.0],
            };
            let gpu = ctx.gpu_encoder();
            gpu.native_enc.draw_instanced(
                composite_pipeline,
                target,
                &[
                    GpuBinding::Bytes {
                        binding: 0,
                        data: bytemuck::bytes_of(&composite_uniforms),
                    },
                    GpuBinding::Texture { binding: 1, texture: inscatter },
                    GpuBinding::Texture { binding: 2, texture: half_depth },
                    GpuBinding::Texture { binding: 3, texture: full_depth },
                ],
                3,
                1,
                manifold_gpu::GpuLoadAction::Load,
                "node.render_scene shaft composite",
            );
        }
    }
}

